import type { ExamQuestion } from "./types";

export const rnCatGiCancerPedsIntegQuestions: ExamQuestion[] = [
  // === CAT - CIRRHOSIS (15 questions) ===
  { q: "A nurse receives report on four cirrhotic patients. Which requires immediate assessment?", o: ["Patient with mild pruritus and jaundice", "Patient with asterixis who has not received lactulose in 12 hours and whose mental status is declining", "Patient with stable ascites awaiting scheduled paracentesis", "Patient with well-controlled encephalopathy on rifaximin"], a: 1, r: "Declining mental status with missed lactulose doses indicates worsening hepatic encephalopathy requiring immediate intervention. Asterixis with missed lactulose and deteriorating consciousness is a time-sensitive finding.", s: "CAT - Cirrhosis" },
  { q: "A cirrhotic patient on the transplant list develops fever (39.1°C), diffuse abdominal pain, and confusion. Paracentesis reveals PMN count of 380/mm3. The nurse anticipates all of the following EXCEPT:", o: ["IV cefotaxime administration", "IV albumin infusion", "Stat CT scan of abdomen before any treatment", "Serial neurological assessments"], a: 2, r: "SBP diagnosis is confirmed by PMN >250/mm3. Treatment with IV antibiotics should not be delayed for imaging. Cefotaxime is first-line, albumin reduces hepatorenal syndrome risk, and neurological monitoring is essential.", s: "CAT - Cirrhosis" },
  { q: "A client with Child-Pugh C cirrhosis (MELD 28) is admitted with massive hematemesis. After octreotide infusion and emergent EGD with band ligation, hemostasis is achieved. The client's BP is 92/58, HR 118, and Hgb 6.8 g/dL. The nurse's PRIORITY is:", o: ["Administer lactulose 30 mL PO", "Transfuse packed red blood cells targeting Hgb >7 g/dL", "Start propranolol for secondary prophylaxis", "Prepare for TIPS procedure"], a: 1, r: "With hemodynamic instability (tachycardia, hypotension) and critically low hemoglobin after achieving hemostasis, blood transfusion is the priority. In variceal bleeding, target Hgb >7 g/dL with restrictive strategy. Overtransfusion can increase portal pressure.", s: "CAT - Cirrhosis" },
  { q: "A nurse is managing a cirrhotic patient on spironolactone 200 mg and furosemide 80 mg daily. The morning potassium is 5.8 mEq/L. Which action takes priority?", o: ["Hold spironolactone (potassium-sparing diuretic contributing to hyperkalemia)", "Hold furosemide", "Increase furosemide to promote potassium excretion", "Continue both medications and recheck K+ in 24 hours"], a: 0, r: "K+ 5.8 mEq/L is dangerously elevated. Spironolactone is a potassium-sparing diuretic and the likely cause. Hold immediately. Furosemide actually promotes K+ excretion and may be continued. Obtain ECG and notify provider.", s: "CAT - Cirrhosis" },
  { q: "A post-TIPS patient develops acute confusion, agitation, and is unable to follow commands 18 hours after the procedure. The nurse should FIRST:", o: ["Administer a sedative for agitation", "Assess ammonia level and administer lactulose — hepatic encephalopathy is the most common TIPS complication", "Prepare for CT head to rule out stroke", "Contact interventional radiology for TIPS revision"], a: 1, r: "Worsening encephalopathy is the most common TIPS complication (20-30%). The shunt diverts portal blood away from the liver, increasing systemic ammonia. Lactulose and rifaximin are first-line treatments.", s: "CAT - Cirrhosis" },
  { q: "A cirrhotic patient presents with oliguria (0.3 mL/kg/hr), creatinine rising from 1.2 to 2.8 mg/dL over 5 days, and bland urine sediment. BUN:Cr ratio is 25:1. The nurse recognizes this as:", o: ["Acute tubular necrosis", "Type 1 hepatorenal syndrome — functional renal failure from severe splanchnic vasodilation", "Post-renal obstruction", "Dehydration-related prerenal azotemia"], a: 1, r: "Rapidly rising creatinine with bland sediment (no casts) in a cirrhotic patient with oliguria suggests Type 1 HRS. The kidneys are structurally normal but functionally compromised due to severe splanchnic vasodilation and renal vasoconstriction.", s: "CAT - Cirrhosis" },
  { q: "A nurse is educating a cirrhotic patient about diet. Which statement by the patient requires correction?", o: ["I should limit my sodium intake to 2 grams per day", "I should eat adequate protein to prevent muscle wasting", "I should avoid all protein because it worsens my confusion", "I should take lactulose as prescribed to manage my ammonia levels"], a: 2, r: "Protein restriction is no longer recommended for cirrhotic patients. Adequate protein (1.2-1.5 g/kg/day) prevents sarcopenia which worsens outcomes. Branched-chain amino acids may be preferred for encephalopathy-prone patients.", s: "CAT - Cirrhosis" },
  { q: "A cirrhotic patient on propranolol develops an SBP of 82/50 with HR 48 bpm. The nurse should:", o: ["Continue propranolol — the low HR is the therapeutic goal", "Hold propranolol, administer IV fluids, and notify provider — SBP <90 with symptomatic bradycardia requires holding beta-blocker", "Increase propranolol dose for better variceal prophylaxis", "Administer atropine and continue propranolol"], a: 1, r: "While target HR is 55-60 bpm, propranolol must be held when SBP <90 mmHg. Hypotension with significant bradycardia indicates the patient cannot tolerate the current dose. This is especially dangerous in cirrhosis where hemodynamic reserve is limited.", s: "CAT - Cirrhosis" },
  { q: "A nurse receives simultaneous calls about two cirrhotic patients. Patient A has new-onset confusion with serum ammonia 142 mcg/dL. Patient B has acute hematemesis with HR 130 and BP 80/50. Which patient should the nurse assess FIRST?", o: ["Patient A — hepatic encephalopathy needs immediate lactulose", "Patient B — active hemorrhage with hemodynamic instability is immediately life-threatening", "Both can wait for the physician", "Assess alphabetically"], a: 1, r: "Active variceal hemorrhage with hemodynamic instability (tachycardia, hypotension indicating >30% blood volume loss) is immediately life-threatening and takes priority. Encephalopathy is serious but less acutely lethal than exsanguination.", s: "CAT - Cirrhosis" },
  { q: "A cirrhotic patient has a chest tube draining 800 mL of transudative fluid from a right-sided pleural effusion with concurrent ascites. The SAAG is 1.3 g/dL. This is most consistent with:", o: ["Empyema", "Hepatic hydrothorax — ascitic fluid tracking through diaphragmatic defects", "Malignant pleural effusion", "Congestive heart failure effusion"], a: 1, r: "Hepatic hydrothorax occurs when ascitic fluid tracks through microscopic diaphragmatic defects (most commonly right-sided). High SAAG confirms portal hypertension etiology. Treatment focuses on managing the ascites (diuretics, sodium restriction, TIPS).", s: "CAT - Cirrhosis" },
  { q: "A patient with newly diagnosed cirrhosis asks what vaccinations are recommended. The nurse includes all EXCEPT:", o: ["Hepatitis A vaccine", "Hepatitis B vaccine", "Pneumococcal vaccine", "Live attenuated varicella vaccine (if immunosuppressed)"], a: 3, r: "Live vaccines are contraindicated in immunosuppressed cirrhotic patients. HAV, HBV, pneumococcal, and influenza vaccines are recommended. Vaccinate early in disease course when immune response is better.", s: "CAT - Cirrhosis" },
  { q: "A nurse is monitoring a cirrhotic patient receiving fresh frozen plasma before a liver biopsy. The patient develops urticaria, fever, and hypotension. The FIRST action is:", o: ["Slow the infusion rate", "Stop the transfusion immediately and maintain IV access with NS", "Administer diphenhydramine and continue the infusion", "Draw blood cultures"], a: 1, r: "Transfusion reaction symptoms (urticaria, fever, hypotension) require immediate cessation. Maintain IV access with NS for volume support. Notify provider and blood bank. Send blood samples per protocol.", s: "CAT - Cirrhosis" },
  { q: "A cirrhotic patient's family asks why the patient is confused when the ammonia level is normal. The best nursing response is:", o: ["The ammonia test must be wrong — reorder it", "Ammonia levels don't always correlate with encephalopathy severity; clinical assessment using the West Haven criteria is more reliable", "Normal ammonia means no encephalopathy", "The lab must have made an error"], a: 1, r: "Serum ammonia levels correlate poorly with encephalopathy severity in many patients. Clinical assessment (orientation, asterixis, sleep-wake patterns, constructional apraxia) using West Haven criteria is more reliable for guiding treatment.", s: "CAT - Cirrhosis" },
  { q: "A nurse is caring for a cirrhotic patient with tense ascites who develops sudden-onset dyspnea, SpO2 85%, and respiratory distress. After positioning semi-Fowler's and applying oxygen, the NEXT priority is:", o: ["Schedule elective paracentesis for tomorrow", "Prepare for urgent therapeutic paracentesis — tense ascites is causing diaphragmatic compromise", "Administer furosemide IV push", "Obtain a chest X-ray before any intervention"], a: 1, r: "Tense ascites causing acute respiratory compromise requires urgent therapeutic paracentesis to relieve diaphragmatic pressure. This is more immediately effective than diuretics (which take hours/days) and should not wait for imaging.", s: "CAT - Cirrhosis" },
  { q: "A cirrhotic patient on lactulose and rifaximin is being prepared for discharge. Which discharge instruction is MOST important?", o: ["Return to the ER if you notice any abdominal swelling", "Call your doctor if you develop fever, confusion, or increased drowsiness — these may indicate infection or worsening encephalopathy requiring immediate evaluation", "Take your medications only when you feel confused", "You can safely take ibuprofen for headaches"], a: 1, r: "Fever may indicate SBP, confusion may indicate worsening encephalopathy — both are emergencies in cirrhosis. Medications should be taken as scheduled (not PRN). NSAIDs are contraindicated.", s: "CAT - Cirrhosis" },

  // === CAT - HEPATITIS (15 questions) ===
  { q: "A pregnant healthcare worker sustains a needlestick from a patient with unknown HBV status. She is vaccinated with anti-HBs of 15 mIU/mL. The BEST action is:", o: ["Administer HBIG immediately", "No action needed — she has adequate immunity (anti-HBs >10)", "Start hepatitis B vaccine series", "Test the source patient and wait for results before acting"], a: 1, r: "Anti-HBs >10 mIU/mL indicates adequate immunity from vaccination. No post-exposure prophylaxis is needed regardless of source patient status.", s: "CAT - Hepatitis" },
  { q: "A patient on entecavir for chronic HBV wants to discontinue the medication because they feel well and their viral load is undetectable. The nurse should educate:", o: ["It is safe to stop when viral load is undetectable", "Abrupt discontinuation risks severe hepatic flare from viral rebound — the medication must be continued or tapered under medical supervision", "Switch to interferon instead", "Stop the medication and monitor labs monthly"], a: 1, r: "HBV antivirals suppress but rarely eliminate the virus. Stopping allows rapid viral rebound that triggers immune-mediated hepatic flare, potentially causing fulminant hepatitis.", s: "CAT - Hepatitis" },
  { q: "A patient starting sofosbuvir/velpatasvir for HCV is also taking amiodarone for atrial fibrillation. The nurse's MOST important action is:", o: ["Proceed with treatment as prescribed", "Alert the prescriber — sofosbuvir + amiodarone can cause life-threatening symptomatic bradycardia", "Monitor heart rate every 4 hours", "Discontinue amiodarone immediately without consulting cardiology"], a: 1, r: "This is a critical drug interaction that can cause cardiac arrest. The prescriber must be notified before initiating therapy. Cardiology consultation is needed for amiodarone management — do not unilaterally discontinue.", s: "CAT - Hepatitis" },
  { q: "A patient has these results: HBsAg+, HBeAg+, anti-HBc IgM+, anti-HBs−, HBV DNA 850,000 IU/mL. This pattern indicates:", o: ["Chronic hepatitis B", "Acute hepatitis B with high infectivity", "Immunity from vaccination", "Window period"], a: 1, r: "HBsAg+ with anti-HBc IgM+ (not IgG) indicates ACUTE infection. HBeAg+ and very high viral load confirm high replication and infectivity. Chronic infection would show anti-HBc IgG (not IgM).", s: "CAT - Hepatitis" },
  { q: "A nurse is caring for a patient with chronic HCV who has achieved SVR (undetectable viral load 12 weeks post-treatment). The patient asks if they still need liver cancer surveillance. The BEST response is:", o: ["No — you are cured and need no further monitoring", "If you had cirrhosis before treatment, you still need HCC surveillance every 6 months — SVR reduces but does not eliminate cancer risk in cirrhotic patients", "Only if symptoms develop", "Annual screening is sufficient"], a: 1, r: "SVR is a virologic cure, but patients with established cirrhosis retain elevated HCC risk. Continue AFP and ultrasound every 6 months. Patients without cirrhosis at SVR generally do not need ongoing HCC surveillance.", s: "CAT - Hepatitis" },
  { q: "A patient with chronic HBV is in the third trimester of pregnancy with HBV DNA of 250,000 IU/mL. The nurse anticipates the provider will order:", o: ["No intervention until after delivery", "Tenofovir to reduce viral load and decrease vertical transmission risk", "Cesarean section only", "Hepatitis B vaccine for the mother"], a: 1, r: "Maternal viral load >200,000 IU/mL in the third trimester significantly increases vertical transmission risk despite HBIG + vaccine at birth. Tenofovir (pregnancy category B) reduces maternal viral load and decreases transmission.", s: "CAT - Hepatitis" },
  { q: "A food handler at a restaurant is diagnosed with hepatitis A. The county health department should be notified because:", o: ["HAV is not reportable", "HAV is a reportable disease; exposed patrons may need post-exposure prophylaxis within 2 weeks", "Only hepatitis B is reportable", "Only if the food handler has symptoms"], a: 1, r: "HAV is a reportable disease. Exposed individuals need PEP (vaccine ± IG depending on age/health status) within 2 weeks. The health department coordinates exposure investigation and prophylaxis.", s: "CAT - Hepatitis" },
  { q: "A nurse is reviewing lab results for a patient being screened for hepatitis. Anti-HCV is positive but HCV RNA (viral load) is undetectable. This means:", o: ["The patient has active HCV and needs treatment", "The patient had prior HCV exposure but has either cleared the infection naturally or been cured — anti-HCV remains positive for life", "The test is invalid", "The patient needs immediate treatment"], a: 1, r: "Anti-HCV indicates exposure (past or present). Undetectable HCV RNA means no active viral replication — the patient either spontaneously cleared the virus (15-25%) or was previously treated and cured. Anti-HCV remains positive for life.", s: "CAT - Hepatitis" },
  { q: "A patient with hepatitis B and hepatitis D superinfection is deteriorating rapidly with coagulopathy (INR 4.5), encephalopathy, and jaundice. The nurse recognizes this presentation as:", o: ["Typical chronic hepatitis", "Fulminant hepatic failure — HDV superinfection has the worst prognosis and highest risk of fulminant hepatitis", "Medication side effect", "Normal disease progression"], a: 1, r: "HDV superinfection (HDV acquired by a chronic HBV carrier) has worse prognosis than coinfection, with highest risk of fulminant hepatitis. Rapid coagulopathy, encephalopathy, and jaundice indicate hepatic failure requiring urgent transplant evaluation.", s: "CAT - Hepatitis" },
  { q: "A patient with chronic HCV develops new-onset palpable purpura on the legs, arthralgias, and proteinuria. The nurse suspects:", o: ["Drug allergy", "Mixed cryoglobulinemia — an extrahepatic manifestation of HCV", "Lupus", "Contact dermatitis"], a: 1, r: "HCV-associated mixed cryoglobulinemia causes vasculitis presenting with palpable purpura, arthralgias, and glomerulonephritis. Treating the HCV with DAAs often resolves the cryoglobulinemia.", s: "CAT - Hepatitis" },
  { q: "A nurse is counseling a patient newly diagnosed with hepatitis B. The patient asks when sexual partners should be tested. The BEST response is:", o: ["Partners don't need testing if they've been vaccinated", "All sexual partners and household contacts should be tested for HBV markers AND vaccinated if non-immune", "Only partners with symptoms need testing", "Partners should wait 6 months before testing"], a: 1, r: "All sexual partners and household contacts should be tested (HBsAg, anti-HBs, anti-HBc) and offered vaccination if non-immune. Use condoms until partner immunity is confirmed.", s: "CAT - Hepatitis" },
  { q: "A patient on DAA therapy for HCV is also HBsAg-positive. Two weeks into treatment, LFTs dramatically increase. The nurse suspects:", o: ["DAA hepatotoxicity", "HBV reactivation during HCV treatment — requires immediate HBV DNA testing and antiviral therapy", "HAV superinfection", "Normal treatment response"], a: 1, r: "HBV reactivation can occur during HCV DAA treatment as immune surveillance shifts. This is why HBV screening is mandatory before starting DAAs. Immediate HBV DNA testing and antiviral therapy are needed.", s: "CAT - Hepatitis" },
  { q: "A nurse is teaching a patient with hepatitis C about transmission prevention. Which patient statement requires further education?", o: ["I should not share razors or toothbrushes", "I should inform healthcare providers about my diagnosis", "I cannot donate blood", "I need to use bleach to clean all dishes after I eat"], a: 3, r: "HCV is bloodborne, not transmitted through casual contact or shared dishes. Standard dishwashing is adequate. Bleaching dishes is unnecessary and indicates the patient misunderstands transmission routes.", s: "CAT - Hepatitis" },
  { q: "A patient with chronic HBV has been on tenofovir for 5 years. The annual creatinine has risen from 0.9 to 1.6 mg/dL. The nurse should:", o: ["Continue medication as prescribed", "Report to the provider — tenofovir disoproxil fumarate can cause nephrotoxicity; may need switch to tenofovir alafenamide (TAF)", "Stop tenofovir immediately", "This is a normal finding"], a: 1, r: "TDF has known nephrotoxic potential with long-term use. Rising creatinine requires evaluation and potential switch to TAF (tenofovir alafenamide), which has significantly less renal toxicity.", s: "CAT - Hepatitis" },
  { q: "A nurse is prioritizing care for four patients with hepatitis. Which patient needs assessment FIRST?", o: ["Chronic HBV patient with normal LFTs", "Acute HAV patient with nausea and fatigue", "Acute HBV patient with INR 3.8 and confusion (possible fulminant hepatitis)", "Chronic HCV patient awaiting DAA therapy"], a: 2, r: "Acute HBV with elevated INR and confusion indicates possible fulminant hepatic failure — a life-threatening emergency requiring immediate assessment, intervention, and potential transplant evaluation.", s: "CAT - Hepatitis" },

  // === CAT - PANCREATITIS (15 questions) ===
  { q: "A patient with acute pancreatitis has been NPO for 72 hours with persistent ileus. The provider orders TPN. The nurse should:", o: ["Initiate TPN as ordered", "Advocate for enteral nutrition via nasojejunal tube — EN is superior to TPN with lower infection rates and better outcomes", "Continue NPO without nutritional support", "Start oral feeding immediately"], a: 1, r: "Evidence strongly supports EN over TPN in pancreatitis. EN maintains gut integrity, reduces bacterial translocation, and decreases infectious complications. The nurse should advocate for the evidence-based approach.", s: "CAT - Pancreatitis" },
  { q: "A patient with acute pancreatitis on day 10 develops new fever (39.5°C), leukocytosis (WBC 22,000), and worsening abdominal pain. CT shows pancreatic necrosis with gas bubbles. The nurse anticipates:", o: ["Oral antibiotics only", "IV carbapenems and CT-guided fine needle aspiration to confirm infected necrosis", "Immediate surgical debridement", "Watchful waiting"], a: 1, r: "Gas bubbles in pancreatic necrosis on CT strongly suggest infected necrosis. IV antibiotics with pancreatic penetration (carbapenems) and FNA for culture confirmation are indicated. Surgery is reserved for failed medical/radiologic management.", s: "CAT - Pancreatitis" },
  { q: "A patient admitted with acute pancreatitis has a lipase of 1,850 U/L, WBC 18,000, glucose 240 mg/dL, and AST 280 U/L. The nurse suspects the etiology is:", o: ["Alcohol-related pancreatitis", "Gallstone pancreatitis — elevated AST suggests biliary etiology", "Hypertriglyceridemia", "Drug-induced"], a: 1, r: "Elevated AST (>3× normal) in pancreatitis has >95% positive predictive value for gallstone etiology. This patient likely has a stone at the ampulla of Vater causing both biliary obstruction (elevated AST) and pancreatitis.", s: "CAT - Pancreatitis" },
  { q: "A pancreatitis patient's serum calcium drops to 6.8 mg/dL. The nurse observes carpopedal spasm when the BP cuff is inflated. This sign is called:", o: ["Chvostek sign", "Trousseau sign — positive indicates symptomatic hypocalcemia from fat saponification", "Kernig sign", "Homans sign"], a: 1, r: "Trousseau sign (carpopedal spasm with BP cuff inflation) indicates symptomatic hypocalcemia. In pancreatitis, calcium is consumed through fat saponification. This is a Ranson criterion indicating severe disease.", s: "CAT - Pancreatitis" },
  { q: "A patient with mild gallstone pancreatitis has resolving symptoms on day 3. The surgical team plans cholecystectomy in 6 weeks. The nurse should advocate for:", o: ["Discharge without surgery", "Index admission cholecystectomy — delaying increases recurrence risk to 30-40%", "Surgery in 6 months", "Medical management only"], a: 1, r: "Evidence supports same-admission cholecystectomy for mild gallstone pancreatitis. Delaying cholecystectomy carries 30-40% recurrence risk. The nurse should advocate for the evidence-based approach.", s: "CAT - Pancreatitis" },
  { q: "A pancreatitis patient has received 8 liters of IV fluid in 12 hours but UOP remains 0.3 mL/kg/hr. SpO2 has dropped to 91% and crackles are heard bilaterally. The nurse should:", o: ["Continue aggressive hydration", "Reduce fluid rate and notify provider — third-spacing may be causing pulmonary edema while intravascular depletion continues", "Stop all fluids", "Give furosemide 80 mg IV push"], a: 1, r: "This represents a complex scenario: third-spacing causes intravascular depletion (low UOP) but extravasated fluid causes pulmonary edema (crackles, low SpO2). Fluid management needs careful titration with possible vasopressor support.", s: "CAT - Pancreatitis" },
  { q: "A patient 6 weeks post-pancreatitis presents with early satiety, nausea, and a palpable epigastric mass. CT shows a 9 cm fluid collection with a defined capsule. The nurse anticipates:", o: ["No intervention needed", "Endoscopic or surgical drainage of symptomatic pancreatic pseudocyst (>6 cm and symptomatic)", "Immediate surgery", "IV antibiotics"], a: 1, r: "Pseudocysts >6 cm that are symptomatic or enlarging require drainage. Endoscopic transmural drainage is preferred. Wait at least 4-6 weeks for wall maturation before intervention.", s: "CAT - Pancreatitis" },
  { q: "A patient with pancreatitis develops sudden-onset sharp pleuritic chest pain, tachypnea, and SpO2 of 88%. The nurse considers which complication FIRST?", o: ["ARDS from systemic inflammatory response", "Pulmonary embolism from immobility — both are possible, but pleuritic pain and acute desaturation favor PE evaluation first", "Left pleural effusion", "Myocardial infarction"], a: 1, r: "While ARDS is common in pancreatitis, sudden-onset pleuritic chest pain with acute desaturation is more consistent with PE. Both are possible — CT angiography helps differentiate. Pancreatitis patients are at high DVT/PE risk from inflammation and immobility.", s: "CAT - Pancreatitis" },
  { q: "A patient with alcoholic pancreatitis asks when they can drink alcohol again. The BEST response is:", o: ["After your pancreas heals in 6 months", "Complete and permanent alcohol abstinence is essential — even small amounts can trigger recurrence and accelerate progression to chronic pancreatitis", "Moderate drinking is acceptable after recovery", "Social drinking only is fine"], a: 1, r: "Alcohol abstinence must be lifelong after alcoholic pancreatitis. Any alcohol can trigger recurrence and progressive chronic pancreatic damage. Refer for addiction counseling and support.", s: "CAT - Pancreatitis" },
  { q: "A nurse is managing pain for a pancreatitis patient. The patient rates pain 9/10 despite hydromorphone 1 mg IV every 3 hours. The nurse should:", o: ["Continue current regimen — 9/10 pain is expected", "Request PCA pump, consider increasing dose or adding multimodal analgesia — pain should be aggressively managed", "Switch to meperidine", "Give aspirin instead"], a: 1, r: "Uncontrolled pain increases catecholamines and worsens outcomes. PCA or dose escalation is appropriate. Add non-opioid adjuncts (ketorolac if no renal/GI issues). Meperidine is falling out of favor due to seizure risk.", s: "CAT - Pancreatitis" },
  { q: "A patient presents with recurrent pancreatitis episodes, steatorrhea (oily floating stools), and new-onset diabetes. These findings indicate:", o: ["Acute pancreatitis recurrence", "Transition to chronic pancreatitis with exocrine (steatorrhea) and endocrine (diabetes) insufficiency", "Gallstone disease", "Celiac disease"], a: 1, r: "Recurrent episodes with progressive exocrine insufficiency (steatorrhea from fat malabsorption) and endocrine failure (diabetes from islet destruction) indicate chronic pancreatitis. CT may show calcifications.", s: "CAT - Pancreatitis" },
  { q: "A patient with acute pancreatitis is improving on day 4 and tolerating clear liquids. The nurse should recommend advancing to:", o: ["Regular high-fat diet", "Low-fat solid diet with small frequent meals — fat is the strongest pancreatic stimulant", "NPO for 7 more days", "Full liquid diet only for 2 weeks"], a: 1, r: "Early advancement to low-fat solid diet is now preferred over prolonged NPO or clear liquids. Fat strongly stimulates CCK-mediated pancreatic enzyme secretion, so fat restriction is important.", s: "CAT - Pancreatitis" },
  { q: "A nurse is calculating the BISAP score for a pancreatitis patient: BUN 28, impaired mental status present, SIRS criteria met, age 62, pleural effusion on CXR. The score of 4 indicates:", o: ["Mild pancreatitis", "Severe pancreatitis with high mortality risk — ICU level care needed", "Moderate pancreatitis", "Score is not prognostic"], a: 1, r: "BISAP ≥3 predicts severe pancreatitis with significantly increased mortality. BUN >25 (1), Impaired mental status (1), SIRS (1), Age >60 (1), Pleural effusion (1) = BISAP 5. ICU monitoring is indicated.", s: "CAT - Pancreatitis" },
  { q: "A patient with hypertriglyceridemia-induced pancreatitis has triglycerides of 2,800 mg/dL. In addition to NPO and IV fluids, the nurse anticipates:", o: ["Statin therapy alone", "Insulin infusion — insulin activates lipoprotein lipase to rapidly lower triglycerides", "Fibrate therapy immediately", "Plasmapheresis only"], a: 1, r: "Insulin infusion activates lipoprotein lipase, which breaks down triglycerides. This is the fastest pharmacologic method to lower extremely elevated TG levels. Heparin can also activate LPL but increases bleeding risk.", s: "CAT - Pancreatitis" },
  { q: "A pancreatitis patient develops blood glucose readings consistently >250 mg/dL requiring insulin. The nurse understands this hyperglycemia:", o: ["Is a side effect of IV fluids", "Results from islet cell destruction and may become permanent — requires ongoing monitoring even after discharge", "Will resolve spontaneously", "Is not related to pancreatitis"], a: 1, r: "Inflammatory destruction of islets of Langerhans causes hyperglycemia. Some patients develop permanent diabetes (type 3c) after severe necrotizing pancreatitis. Long-term glucose monitoring is essential.", s: "CAT - Pancreatitis" },

  // === CAT - GI BLEEDING (15 questions) ===
  { q: "A patient arrives with hematemesis and is hemodynamically unstable (HR 135, BP 78/42). Two large-bore IVs are placed and fluid resuscitation begun. The nurse should simultaneously:", o: ["Insert a Foley catheter only", "Activate massive transfusion protocol, draw type and cross, and prepare for emergent EGD", "Wait for labs before acting", "Give oral PPI"], a: 1, r: "Massive hemorrhage with hemodynamic instability requires simultaneous resuscitation and preparation for definitive therapy. Massive transfusion protocol provides rapid access to blood products.", s: "CAT - GI Bleeding" },
  { q: "A cirrhotic patient with known varices presents with massive hematemesis. While preparing for EGD, the nurse should anticipate orders for all EXCEPT:", o: ["Octreotide 50 mcg IV bolus then infusion", "Ceftriaxone 1 g IV (antibiotic prophylaxis)", "Recombinant factor VIIa for all variceal bleeds", "Type and crossmatch for blood"], a: 2, r: "Recombinant factor VIIa is NOT standard for variceal bleeding. Standard management includes octreotide, antibiotic prophylaxis (ceftriaxone), blood products, and emergent endoscopy.", s: "CAT - GI Bleeding" },
  { q: "An elderly patient on warfarin (INR 5.2) presents with melena and hemoglobin 7.8 g/dL. The nurse's PRIORITY action sequence is:", o: ["Give vitamin K and wait for INR correction", "Establish large-bore IV access, hold warfarin, administer PCC (prothrombin complex concentrate) for immediate reversal, transfuse PRBCs, arrange EGD", "Start oral PPI and observe", "Discharge with outpatient follow-up"], a: 1, r: "Active GI bleeding with supratherapeutic INR requires immediate action: IV access, hold anticoagulant, PCC for immediate factor replacement (faster than FFP or vitamin K alone), transfuse for Hgb <7, and arrange EGD.", s: "CAT - GI Bleeding" },
  { q: "A patient with a high-risk peptic ulcer (visible vessel at base) undergoes endoscopic hemostasis. Post-EGD, the nurse notes the provider ordered omeprazole 20 mg PO daily. The nurse should:", o: ["Administer as ordered", "Question the order — high-risk ulcers require IV PPI bolus + continuous infusion (pantoprazole 80 mg then 8 mg/hr × 72 hours)", "Add ranitidine", "Give antacids instead"], a: 1, r: "The nurse should advocate for the evidence-based protocol: high-dose IV PPI (bolus + infusion × 72 hours) for high-risk ulcers. Oral PPI at a standard dose is insufficient for maintaining gastric pH >6 needed to stabilize the clot.", s: "CAT - GI Bleeding" },
  { q: "A patient with acute UGIB has a Glasgow-Blatchford Score of 0. The ER is busy with multiple critical patients. The appropriate disposition is:", o: ["ICU admission", "Immediate EGD", "Safe for discharge with outpatient EGD — GBS 0 identifies patients who will NOT need hospital-based intervention", "Hold in ER for 24 hours"], a: 2, r: "GBS of 0 has excellent sensitivity for identifying patients who will not need any intervention. These patients can be safely discharged with outpatient follow-up, freeing hospital resources for sicker patients.", s: "CAT - GI Bleeding" },
  { q: "A patient who had coronary stent placement 3 months ago presents with peptic ulcer bleeding while on dual antiplatelet therapy. The cardiologist recommends continuing clopidogrel but stopping aspirin. The nurse understands this decision balances:", o: ["There is no concern about stopping antiplatelets", "GI bleeding risk vs cardiovascular risk (stent thrombosis within 12 months of placement carries very high mortality)", "Only the GI team's recommendation matters", "Both drugs should be permanently stopped"], a: 1, r: "Within 12 months of stent placement, stopping dual antiplatelet therapy risks stent thrombosis (>50% mortality). Decisions require multidisciplinary input balancing bleeding risk against cardiovascular catastrophe.", s: "CAT - GI Bleeding" },
  { q: "A nurse notices an elderly patient's hemoglobin has dropped from 12 to 8 g/dL over 3 months with guaiac-positive stools and iron deficiency anemia. The nurse recognizes the need for:", o: ["Iron supplementation alone", "Colonoscopy to rule out colorectal cancer — chronic occult GI bleeding with iron deficiency in the elderly is cancer until proven otherwise", "Observation", "Stool culture"], a: 1, r: "Chronic occult GI bleeding causing iron deficiency anemia in an elderly patient must be evaluated with colonoscopy to rule out colorectal malignancy. Iron supplementation without investigation is insufficient.", s: "CAT - GI Bleeding" },
  { q: "A patient with massive LGIB has negative colonoscopy. The bleeding rate is estimated at 1 mL/min. The BEST diagnostic study is:", o: ["Repeat colonoscopy", "CT angiography — detects active bleeding >0.5 mL/min with anatomic localization", "Barium enema", "Capsule endoscopy"], a: 1, r: "CT angiography is the study of choice for active LGIB with negative colonoscopy. It detects bleeding >0.3-0.5 mL/min and provides anatomic localization for potential embolization or surgical planning.", s: "CAT - GI Bleeding" },
  { q: "A nurse is caring for a patient who had EGD with variceal band ligation 6 hours ago. The patient reports sudden chest pain and difficulty swallowing. The nurse suspects:", o: ["Anxiety", "Post-banding ulcer perforation or esophageal perforation — emergent evaluation needed", "Normal post-procedure discomfort", "Heartburn"], a: 1, r: "Chest pain and dysphagia post-variceal banding may indicate esophageal perforation or post-banding ulcer complication. This requires urgent evaluation with imaging (chest X-ray, CT) and possible surgical consultation.", s: "CAT - GI Bleeding" },
  { q: "A patient with a Forrest classification Ia ulcer (spurting arterial bleeding) has endoscopic hemostasis with epinephrine injection alone. The nurse anticipates:", o: ["This is adequate treatment", "A second hemostatic modality should be added — dual therapy (epinephrine + clip or thermal) is superior to epinephrine alone for high-risk lesions", "No further intervention", "Discharge planning"], a: 1, r: "Epinephrine monotherapy has higher rebleeding rates than dual therapy. Guidelines recommend combining epinephrine with a second modality (hemoclip, bipolar cautery) for high-risk lesions (Forrest Ia/Ib).", s: "CAT - GI Bleeding" },
  { q: "A nurse receives four patients from the ER. Which GI bleeding patient needs immediate assessment?", o: ["Patient with coffee-ground emesis, stable vitals, Hgb 10.5", "Patient with bright red hematemesis, HR 128, BP 84/50, diaphoretic", "Patient with melena, stable vitals, Hgb 9.8", "Patient with occult blood positive stool, no symptoms"], a: 1, r: "Active hematemesis with hemodynamic instability (tachycardia, hypotension, diaphoresis) indicates massive hemorrhage with >30% blood volume loss — immediately life-threatening.", s: "CAT - GI Bleeding" },
  { q: "A patient with recurrent UGIB from a Dieulafoy lesion has failed two endoscopic attempts. The nurse prepares for:", o: ["Third endoscopy attempt", "Interventional radiology angiographic embolization as the next step when endoscopy fails", "Oral PPI therapy alone", "Observation and serial hemoglobin checks"], a: 1, r: "After two failed endoscopic attempts, interventional radiology angiographic embolization is the next step. Surgery is reserved for failure of both endoscopic and radiologic interventions.", s: "CAT - GI Bleeding" },
  { q: "A patient on dabigatran presents with acute upper GI bleeding. The nurse anticipates the reversal agent:", o: ["Vitamin K", "Protamine", "Idarucizumab (Praxbind) — specific dabigatran reversal agent", "Fresh frozen plasma"], a: 2, r: "Idarucizumab is the monoclonal antibody fragment that specifically reverses dabigatran. It provides complete reversal within minutes. Vitamin K reverses warfarin; protamine reverses heparin.", s: "CAT - GI Bleeding" },
  { q: "A patient with portal hypertensive gastropathy has chronic, slow GI bleeding causing iron deficiency anemia (Hgb 8.5) but no active hemorrhage. The nurse anticipates management with:", o: ["Emergent EGD with cauterization", "Non-selective beta-blocker (to reduce portal pressure) and iron supplementation", "Immediate surgery", "Proton pump inhibitor alone"], a: 1, r: "Portal hypertensive gastropathy causes diffuse mucosal changes that cannot be treated endoscopically. Management is medical: reduce portal pressure with beta-blockers and correct iron deficiency.", s: "CAT - GI Bleeding" },
  { q: "Following massive upper GI bleeding requiring 8 units of PRBCs, a patient develops hypocalcemia (Ca 6.9) and prolonged QTc. The nurse understands this is caused by:", o: ["Underlying pancreatitis", "Citrate toxicity from blood products — citrate binds calcium in transfused blood", "Vitamin D deficiency", "Renal failure"], a: 1, r: "Massive transfusion introduces large amounts of citrate (anticoagulant in blood products) that chelates ionized calcium. This can cause symptomatic hypocalcemia, prolonged QTc, and cardiac instability. Calcium gluconate replaces depleted calcium.", s: "CAT - GI Bleeding" },

  // === CAT - BOWEL OBSTRUCTION (15 questions) ===
  { q: "A nurse is caring for a patient with small bowel obstruction on conservative management. After 48 hours, the patient develops constant (no longer colicky) severe pain, fever 39.2°C, and WBC 22,000 with left shift. The nurse should:", o: ["Continue conservative management", "Notify the surgeon immediately — transition from colicky to constant pain with systemic signs indicates strangulation requiring urgent surgical exploration", "Increase NG suction", "Administer metoclopramide"], a: 1, r: "The shift from intermittent colicky pain to constant severe pain is the critical warning sign of strangulation. Combined with fever and leukocytosis, this indicates bowel ischemia/necrosis requiring emergent surgery. Time is critical.", s: "CAT - Bowel Obstruction" },
  { q: "A post-appendectomy patient develops abdominal distension and vomiting on day 3. X-ray shows dilated small bowel loops. Before determining if this is mechanical obstruction or paralytic ileus, the nurse assesses for:", o: ["Temperature only", "Bowel sound character (high-pitched/tinkling suggests mechanical; absent suggests ileus) and pain pattern (colicky vs constant)", "Skin color", "Blood pressure only"], a: 1, r: "The key differentiating features are bowel sounds (high-pitched = mechanical, absent = ileus) and pain pattern (colicky = mechanical, constant/absent = ileus). Management differs significantly: mechanical may need surgery; ileus is managed conservatively.", s: "CAT - Bowel Obstruction" },
  { q: "An 8-month-old presents with sudden colicky crying episodes, drawing legs up, and a sausage-shaped RUQ mass. Between episodes the child appears normal. After initial stabilization, the nurse anticipates:", o: ["Immediate surgery", "Air or hydrostatic enema for intussusception reduction — this is both diagnostic and therapeutic", "Barium swallow", "Observation only"], a: 1, r: "Classic intussusception presentation in a child 6 months to 3 years. Air or hydrostatic enema is the first-line treatment (non-surgical reduction successful in 80-95%). Surgery is reserved for failed enema or perforation.", s: "CAT - Bowel Obstruction" },
  { q: "A patient with known sigmoid volvulus has been successfully decompressed by sigmoidoscopy. The nurse teaches the patient that:", o: ["The problem is permanently fixed", "Elective sigmoid resection is recommended because recurrence rate is 40-60% without surgery", "No follow-up is needed", "Repeat decompression is always effective"], a: 1, r: "Sigmoid volvulus has 40-60% recurrence after decompression alone. Elective sigmoid resection is recommended to prevent recurrence and the risk of strangulation with subsequent episodes.", s: "CAT - Bowel Obstruction" },
  { q: "A nurse notes that a patient with SBO on NG decompression has increased NG output (now 1.5 L/day), and the serum chloride is 88 mEq/L with pH 7.52. The nurse recognizes:", o: ["Normal findings", "Hypochloremic metabolic alkalosis from prolonged NG suctioning of gastric acid — replace chloride with IV NS", "Respiratory alkalosis", "Metabolic acidosis"], a: 1, r: "Prolonged NG suctioning removes HCl (hydrogen and chloride), causing hypochloremic metabolic alkalosis. The kidneys excrete K+ to retain H+, worsening hypokalemia. Replace with NS (contains Cl-) and monitor potassium.", s: "CAT - Bowel Obstruction" },
  { q: "A patient with large bowel obstruction from sigmoid colon cancer has cecal diameter of 11 cm on CT. The nurse understands this is urgent because:", o: ["Cecal diameter >9-12 cm has high risk of perforation from back-pressure", "It indicates a small bowel obstruction instead", "This is a normal cecal diameter", "It only requires outpatient follow-up"], a: 0, r: "In LBO with competent ileocecal valve, the cecum acts as a closed-loop segment. Cecal dilation >9-12 cm carries high perforation risk from progressive distension (Law of LaPlace). Urgent decompression or surgery is needed.", s: "CAT - Bowel Obstruction" },
  { q: "A patient with partial adhesive SBO received Gastrografin via NG tube 8 hours ago. X-ray shows contrast has reached the colon. This indicates:", o: ["Need for surgery", "The obstruction has resolved or is resolving — continue conservative management and advance diet as tolerated", "Bowel perforation", "The test is inconclusive"], a: 1, r: "Contrast reaching the colon within 24 hours indicates patent bowel and predicts successful conservative management. If contrast fails to reach the colon by 24-48 hours, surgical intervention is more likely needed.", s: "CAT - Bowel Obstruction" },
  { q: "A nurse is monitoring an SBO patient's serum lactate. Over 6 hours it has risen from 1.8 to 5.4 mmol/L despite adequate IV fluid resuscitation. This trend indicates:", o: ["Adequate resuscitation", "Progressive bowel ischemia from strangulation — notify surgeon for possible exploration", "Normal variation", "Dehydration only"], a: 1, r: "Persistently rising lactate despite adequate resuscitation indicates ongoing tissue ischemia, most likely from strangulated bowel. This is a strong indication for surgical exploration regardless of other clinical findings.", s: "CAT - Bowel Obstruction" },
  { q: "A postoperative patient has paralytic ileus for 5 days. The surgeon considers alvimopan. The nurse knows this medication:", o: ["Can be used for any patient", "Blocks peripheral opioid effects on the GI tract without affecting central analgesia — only for hospitalized patients", "Is an antibiotic", "Increases gut motility through cholinergic stimulation"], a: 1, r: "Alvimopan is a peripheral mu-opioid receptor antagonist (PAMORA). It blocks opioid-induced bowel dysfunction without crossing the blood-brain barrier. Only approved for hospitalized patients with short-term use.", s: "CAT - Bowel Obstruction" },
  { q: "A nurse is caring for a patient with a complete SBO who has been managed conservatively for 72 hours without improvement. Vital signs are stable and labs normal. The nurse should:", o: ["Continue waiting", "Advocate for surgical consultation — complete SBO without improvement in 72 hours typically warrants surgical intervention", "Start oral feeding trial", "Increase NG suction pressure"], a: 1, r: "Complete SBO (no passage of gas or stool at all) that does not resolve with 24-72 hours of conservative management generally requires surgical intervention to prevent progression to strangulation.", s: "CAT - Bowel Obstruction" },
  { q: "A patient with bowel obstruction suddenly vomits large amounts and becomes tachypneic with SpO2 88%. The nurse's FIRST action is:", o: ["Call a code", "Position patient on their side, suction the airway, and apply supplemental oxygen — aspiration prevention is the immediate priority", "Insert NG tube", "Administer antiemetic"], a: 1, r: "Aspiration is an immediate life-threatening complication of vomiting in bowel obstruction. Lateral positioning and suctioning protect the airway. Oxygen supports SpO2. NG tube can be placed after airway is secured.", s: "CAT - Bowel Obstruction" },
  { q: "A patient with incarcerated inguinal hernia has a reducible hernia that the ER physician successfully reduces. The nurse educates the patient about:", o: ["No further treatment needed", "Elective hernia repair is recommended to prevent recurrence and strangulation", "The hernia is permanently fixed", "Apply a truss indefinitely"], a: 1, r: "Successfully reduced incarcerated hernia should be followed by elective surgical repair to prevent recurrence. An incarcerated hernia that becomes strangulated is a surgical emergency with bowel necrosis risk.", s: "CAT - Bowel Obstruction" },
  { q: "A patient recovering from bowel obstruction surgery passes flatus for the first time. The nurse should:", o: ["No significance", "Document this as return of bowel function and begin advancing diet from clear liquids as tolerated", "Start full regular diet immediately", "Continue NPO for 3 more days"], a: 1, r: "Passage of flatus is the most reliable indicator of return of bowel function. Begin advancing diet carefully from clear liquids, progressing as tolerated. This milestone guides the clinical team's discharge planning.", s: "CAT - Bowel Obstruction" },
  { q: "A patient with LBO from sigmoid cancer undergoes emergent surgery. A Hartmann procedure is performed. The nurse explains to the patient that:", o: ["Normal bowel function will resume immediately", "A temporary colostomy was created and the rectal stump was closed — reversal may be possible after recovery and any needed chemotherapy", "The cancer is completely cured", "No further treatment will be needed"], a: 1, r: "Hartmann procedure (sigmoid resection with end colostomy and rectal stump closure) is common for emergent LBO from cancer. Reversal (colostomy takedown and reanastomosis) may be possible after recovery.", s: "CAT - Bowel Obstruction" },
  { q: "A nurse is assessing a patient with bowel obstruction who has had progressively worsening abdominal distension. The patient suddenly reports feeling 'much better' and pain has resolved, but vital signs show HR 132, BP 82/48, and temp 39.8°C. The nurse should:", o: ["Celebrate the improvement in pain", "Recognize this as a critical emergency — sudden pain relief with deteriorating vitals indicates perforation and developing peritonitis", "Remove NG tube since pain resolved", "Discharge the patient"], a: 1, r: "This is the classic 'improvement before catastrophe' scenario. Sudden pain relief in obstruction with worsening hemodynamics and fever = perforation. The intraluminal pressure is released but peritonitis/sepsis develops. This is a surgical emergency.", s: "CAT - Bowel Obstruction" },

  // === CAT - IBD (15 questions) ===
  { q: "A patient with UC develops acute abdominal distension, fever 39.5°C, HR 120, and X-ray shows colonic dilation of 8 cm. The nurse's FIRST action after notifying the surgeon is:", o: ["Administer loperamide for diarrhea", "Ensure the patient is NPO, NG tube for decompression, and hold all medications that decrease colonic motility — this is toxic megacolon", "Give metoclopramide to stimulate motility", "Prepare for colonoscopy"], a: 1, r: "Toxic megacolon (colonic dilation >6 cm with systemic toxicity) is a surgical emergency. NPO, NG tube decompression, and HOLD all motility-reducing drugs (opioids, anticholinergics, loperamide). If no improvement in 24-72 hours, emergent colectomy is needed.", s: "CAT - IBD" },
  { q: "A patient with Crohn disease on infliximab develops a new cough, night sweats, and weight loss. The nurse suspects:", o: ["Common cold", "Tuberculosis reactivation — must screen with CXR and TB testing immediately", "Normal infliximab side effect", "Asthma"], a: 1, r: "Anti-TNF therapy can reactivate latent TB. Cough, night sweats, and weight loss are classic TB symptoms. This is why TB screening is required before starting biologics and why ongoing vigilance is essential.", s: "CAT - IBD" },
  { q: "A nurse receives a call that a patient's TPMT result shows complete enzyme deficiency. The patient is scheduled to start azathioprine tomorrow. The nurse should:", o: ["Proceed with standard dosing", "HOLD the azathioprine and notify the prescriber immediately — complete TPMT deficiency causes life-threatening myelosuppression at standard doses", "Give half the dose", "Wait for repeat testing"], a: 1, r: "Complete TPMT deficiency (1 in 300 patients) causes inability to metabolize thiopurines, leading to fatal myelosuppression. These patients should NEVER receive azathioprine or 6-MP at standard doses.", s: "CAT - IBD" },
  { q: "A patient with Crohn disease presents with RLQ pain, fever, and CT showing an abscess at the ileocecal junction. The nurse anticipates management will include:", o: ["Immediate surgery", "IV antibiotics and CT-guided percutaneous abscess drainage before considering elective surgery", "Oral antibiotics only", "Observation"], a: 1, r: "Crohn-related abscesses are managed with IV antibiotics and percutaneous drainage first. This allows inflammation to subside before any needed surgery, reducing operative risk and enabling more limited resection.", s: "CAT - IBD" },
  { q: "A patient with UC is being started on vedolizumab after failing infliximab. The nurse's MOST important teaching point compared to infliximab is:", o: ["Vedolizumab has more systemic immunosuppression", "Vedolizumab is gut-selective (blocks alpha4beta7 integrin) with lower systemic infection risk compared to anti-TNF agents — but still requires monitoring", "It works faster than infliximab", "No monitoring is needed"], a: 1, r: "Vedolizumab selectively targets gut lymphocyte trafficking without broad systemic immunosuppression. This results in lower risk of systemic infections and TB reactivation compared to anti-TNF agents, though monitoring is still important.", s: "CAT - IBD" },
  { q: "A Crohn patient with a new enterovesical fistula presents with recurrent UTIs and pneumaturia (air in urine). The nurse understands this occurs because:", o: ["UTI is unrelated to Crohn", "Transmural Crohn inflammation has created an abnormal connection between the bowel and bladder allowing fecal contents and gas to enter the urinary tract", "Bladder infection is causing the fistula", "This is a medication side effect"], a: 1, r: "Enterovesical fistula is a complication of transmural Crohn inflammation. Bowel contents entering the bladder cause recurrent polymicrobial UTIs and pneumaturia (pathognomonic finding). Treatment requires surgery and/or biological therapy.", s: "CAT - IBD" },
  { q: "A patient with long-standing UC (15 years) has a surveillance colonoscopy showing high-grade dysplasia. The nurse anticipates the recommendation will be:", o: ["Repeat colonoscopy in 1 year", "Colectomy — high-grade dysplasia in UC carries high risk of concurrent or progression to colorectal cancer", "Increased mesalamine dose", "Observation only"], a: 1, r: "High-grade dysplasia in UC is a strong indication for colectomy because it carries approximately 30-50% risk of concurrent invasive cancer and very high progression risk. Low-grade dysplasia is more debatable.", s: "CAT - IBD" },
  { q: "A pediatric patient with Crohn disease has fallen off the growth curve. Linear growth has stalled despite adequate nutrition. The nurse anticipates the priority intervention is:", o: ["Growth hormone therapy", "Achieve and maintain disease remission — uncontrolled inflammation is the primary driver of growth failure through cytokine-mediated growth suppression", "Increase caloric intake only", "Accept the growth failure as inevitable"], a: 1, r: "Chronic inflammation suppresses the growth hormone/IGF-1 axis through pro-inflammatory cytokines. Achieving remission (often requiring biologics) is essential for catch-up growth, which is still possible if remission is achieved before epiphyseal closure.", s: "CAT - IBD" },
  { q: "A nurse is managing a patient with severe UC flare who has been on IV corticosteroids for 5 days without response (continued bloody diarrhea 10x/day, CRP elevated, ESR >50). The nurse anticipates:", o: ["Continue steroids for 2 more weeks", "Rescue therapy with infliximab or cyclosporine, OR colectomy — steroid-refractory severe UC requires escalation", "Switch to oral steroids", "Discharge with outpatient follow-up"], a: 1, r: "Steroid-refractory severe UC (no response to IV steroids by day 3-5) requires urgent decision: rescue with infliximab or cyclosporine, or proceed to colectomy. Continued steroids without response increases complications without benefit.", s: "CAT - IBD" },
  { q: "A patient with UC J-pouch develops increased stool frequency (15x/day), urgency, and fever 6 months post-surgery. Endoscopy shows diffuse inflammation of the ileal pouch. The nurse anticipates treatment with:", o: ["Total parenteral nutrition", "Metronidazole or ciprofloxacin for pouchitis", "Repeat colectomy", "Immunosuppressive therapy"], a: 1, r: "Pouchitis (inflammation of the J-pouch) occurs in up to 50% of patients and is the most common long-term complication. First-line treatment is antibiotics (metronidazole or ciprofloxacin). Probiotics may help prevent recurrence.", s: "CAT - IBD" },
  { q: "A nurse is caring for a Crohn patient who develops significant perianal disease with a complex fistula. After failed antibiotic therapy, the patient is started on infliximab. The nurse explains that the goal of therapy is:", o: ["Immediate surgical correction", "Fistula healing and closure — infliximab has the best evidence for inducing and maintaining Crohn fistula closure", "Symptom management only", "There is no effective treatment"], a: 1, r: "Infliximab has the strongest evidence for healing Crohn perianal fistulae. The ACCENT II trial showed both induction and maintenance of fistula closure. Surgery (seton placement) is often used as a bridge.", s: "CAT - IBD" },
  { q: "A patient with UC on azathioprine for 2 years develops severe sore throat, fever, and WBC of 1,200 with ANC 180. The nurse's PRIORITY action is:", o: ["Give acetaminophen for fever", "Hold azathioprine immediately, draw blood cultures, and prepare for empiric broad-spectrum antibiotics — this is drug-induced agranulocytosis", "Continue azathioprine and recheck labs tomorrow", "Prescribe oral antibiotics"], a: 1, r: "Severe myelosuppression (WBC 1,200, ANC 180) from azathioprine is a medical emergency. Hold the drug, institute febrile neutropenia protocol (cultures, empiric antibiotics within 60 minutes), and consider G-CSF.", s: "CAT - IBD" },
  { q: "A nurse reviews labs for a Crohn patient: low B12, low iron, elevated ESR, and low prealbumin. The most likely explanation is:", o: ["Poor dietary choices", "Active ileal Crohn disease causing B12 malabsorption (terminal ileum), iron malabsorption, elevated inflammatory markers, and protein-calorie malnutrition", "Celiac disease", "Medication side effect"], a: 1, r: "This lab pattern is classic for active ileal Crohn: B12 absorbed exclusively in terminal ileum (malabsorption), iron malabsorption from duodenal/jejunal inflammation, ESR elevated from inflammation, low prealbumin from malnutrition.", s: "CAT - IBD" },
  { q: "A pregnant patient with UC asks if her medications are safe to continue. She is on mesalamine and azathioprine. The nurse should advise:", o: ["Stop all medications during pregnancy", "Most IBD medications (mesalamine, azathioprine) are safer than uncontrolled disease — active disease poses greater risk to the pregnancy than continued medication", "Switch to methotrexate", "Only take medications during the first trimester"], a: 1, r: "Active IBD flares during pregnancy increase risk of preterm birth and low birth weight MORE than continued medication. Mesalamine and azathioprine are generally safe. Methotrexate is absolutely contraindicated (teratogenic). Disease control is the priority.", s: "CAT - IBD" },
  { q: "A patient newly diagnosed with indeterminate colitis (cannot distinguish UC from Crohn) asks about surgical options. The nurse explains:", o: ["Immediate colectomy is recommended", "Definitive surgery should be deferred if possible because the surgical approach differs: UC may benefit from J-pouch while Crohn patients should NOT have J-pouch due to high failure rate", "Surgery is the same for both conditions", "No surgery is ever needed"], a: 1, r: "The distinction matters: UC patients can have curative proctocolectomy with J-pouch. Crohn patients should NOT have J-pouch because disease recurrence in the pouch leads to high failure and complication rates. Further workup is needed before surgery.", s: "CAT - IBD" },

  // === CAT - CANCER BIOLOGY (15 questions) ===
  { q: "A patient on cisplatin chemotherapy develops tinnitus and hearing loss. The nurse's PRIORITY action is:", o: ["Document and continue chemotherapy", "Report immediately — ototoxicity may be irreversible and requires audiometric evaluation before the next cycle; dose modification may be needed", "Give acetaminophen for the tinnitus", "This is a temporary side effect"], a: 1, r: "Cisplatin ototoxicity is dose-related and often irreversible. Any hearing changes must be reported immediately for audiometric evaluation before the next cycle. The provider may need to switch agents or modify doses.", s: "CAT - Cancer Biology" },
  { q: "A patient receiving their first infusion of rituximab develops rigors, hypotension (BP 78/42), and bronchospasm within 30 minutes. The nurse should:", o: ["Slow the infusion rate", "Stop the infusion immediately, maintain IV access, administer epinephrine, and follow anaphylaxis protocol — this is an infusion reaction/anaphylaxis", "Continue and give diphenhydramine", "This is expected"], a: 1, r: "Severe infusion reaction with hypotension and bronchospasm requires immediate cessation and anaphylaxis management. Rituximab has high infusion reaction rates. Premedication with acetaminophen, diphenhydramine, and steroids reduces risk.", s: "CAT - Cancer Biology" },
  { q: "A nurse is educating a patient with BRCA1-mutated ovarian cancer about PARP inhibitor therapy. The patient asks how it works. The BEST explanation is:", o: ["It kills all dividing cells", "PARP inhibitors exploit your cancer's inability to repair DNA — cancer cells with BRCA mutations cannot fix certain types of DNA damage, so blocking PARP causes them to accumulate fatal DNA errors while normal cells can still repair", "It boosts the immune system", "It blocks hormones"], a: 1, r: "Synthetic lethality: BRCA-mutated cells already have one DNA repair pathway disabled. PARP inhibitors block the backup pathway. Normal cells have both pathways intact and survive. This selectivity makes PARP inhibitors targeted and less toxic.", s: "CAT - Cancer Biology" },
  { q: "A patient on pembrolizumab for melanoma develops new-onset fatigue, weight gain, and cold intolerance 8 weeks into treatment. TSH is 28 mIU/L. The nurse recognizes this as:", o: ["Normal treatment response", "Immune-related thyroiditis (hypothyroid phase) from checkpoint inhibitor — most common endocrine irAE", "Unrelated thyroid disease", "Drug allergy"], a: 1, r: "Thyroid dysfunction is the most common endocrine immune-related adverse event from checkpoint inhibitors. It often starts with hyperthyroidism (thyroid destruction) then transitions to hypothyroidism. Treat with levothyroxine.", s: "CAT - Cancer Biology" },
  { q: "A nurse is calculating the ANC for a patient scheduled for cycle 3 of chemotherapy: WBC 3,200, segs 35%, bands 5%. Should chemotherapy proceed?", o: ["Yes — ANC is adequate", "No — ANC is 1,280 which is below the typical threshold of 1,500 for administering chemotherapy", "Need more information", "Proceed regardless of ANC"], a: 1, r: "ANC = 3,200 × (0.35 + 0.05) = 1,280. Most protocols require ANC ≥1,500 for chemotherapy. Hold chemotherapy and notify the oncologist. The patient may need G-CSF support or dose reduction for the next cycle.", s: "CAT - Cancer Biology" },
  { q: "A patient with lung cancer is receiving concurrent chemoradiation. They develop odynophagia (painful swallowing) and cannot tolerate oral intake. The nurse suspects:", o: ["Common cold", "Radiation esophagitis from the treatment field — requires pain management, dietary modification, and possibly enteral nutrition support", "Medication side effect", "Anxiety-related dysphagia"], a: 1, r: "Radiation esophagitis is common when the esophagus is within the treatment field (chest radiation). Management includes topical anesthetics (magic mouthwash), PPIs, soft/liquid diet, and nutritional support.", s: "CAT - Cancer Biology" },
  { q: "A patient with newly diagnosed breast cancer has ER+/PR+/HER2− tumor. The nurse anticipates the treatment plan will include:", o: ["Trastuzumab", "Hormonal therapy (tamoxifen or aromatase inhibitor) — receptor-positive tumors respond to hormone receptor blockade", "No targeted therapy possible", "PARP inhibitor"], a: 1, r: "ER+/PR+ tumors are hormone-responsive. Treatment includes anti-hormonal therapy: tamoxifen (premenopausal) or aromatase inhibitors (postmenopausal). HER2− means trastuzumab is NOT indicated.", s: "CAT - Cancer Biology" },
  { q: "A nurse discovers that a vesicant chemotherapy (doxorubicin) has been infiltrating into the forearm tissue for approximately 20 minutes before being noticed. The MOST important interventions include:", o: ["Continue the infusion from a new site", "Stop infusion, aspirate residual, elevate extremity, administer dexrazoxane (within 6 hours), mark the extravasation site, apply cold compresses, and notify the oncologist", "Apply warm compress and resume", "No treatment needed"], a: 1, r: "Anthracycline extravasation can cause tissue necrosis to bone. Dexrazoxane is the specific antidote when given within 6 hours. Do NOT apply heat (worsen damage). Cold compresses slow local spread. Document and photograph.", s: "CAT - Cancer Biology" },
  { q: "A patient with stage IV colon cancer is being evaluated for immunotherapy eligibility. Which biomarker test result would make the patient a candidate for pembrolizumab?", o: ["BRCA mutation", "HER2 overexpression", "MSI-high (microsatellite instability-high) or dMMR (deficient mismatch repair)", "Low PD-L1 expression"], a: 2, r: "MSI-high/dMMR tumors have high mutational burden and neoantigen load, making them responsive to checkpoint inhibitors regardless of tissue of origin. Pembrolizumab was FDA-approved as the first tissue-agnostic cancer therapy for MSI-high tumors.", s: "CAT - Cancer Biology" },
  { q: "A nurse is providing end-of-life care for a cancer patient. The patient's family asks about stopping cancer treatment but continuing comfort measures. The nurse's BEST response is:", o: ["The patient must continue treatment", "Transitioning to comfort-focused care is a valid and compassionate choice — palliative care focuses on quality of life and symptom management without the side effects of cancer treatment", "Only the doctor can make that decision", "Stopping treatment means giving up"], a: 1, r: "Transitioning to comfort care is a dignified choice that prioritizes quality of life. Palliative care manages symptoms (pain, nausea, dyspnea) without treatment side effects. Support the family's informed decision.", s: "CAT - Cancer Biology" },
  { q: "A patient receiving bleomycin develops a new dry cough and exertional dyspnea. PFTs show decreased DLCO. The nurse should:", o: ["Administer a cough suppressant", "Report immediately — bleomycin pulmonary toxicity (pneumonitis/fibrosis) requires stopping the drug and evaluation; it can be fatal", "Continue treatment and monitor", "Give bronchodilator"], a: 1, r: "Bleomycin causes dose-dependent pulmonary toxicity (pneumonitis progressing to fibrosis). Decreased DLCO is the earliest PFT finding. Stop bleomycin immediately. Risk increases with cumulative dose, age >70, and supplemental O2.", s: "CAT - Cancer Biology" },
  { q: "A patient with cancer-related bone metastases is receiving zoledronic acid. Before each infusion, the nurse checks:", o: ["Blood glucose", "Serum creatinine — bisphosphonates can cause nephrotoxicity; also assess for osteonecrosis of the jaw (ONJ) symptoms", "Thyroid function", "Coagulation studies"], a: 1, r: "Zoledronic acid is nephrotoxic — check creatinine before each dose. Also assess for jaw pain (ONJ risk increases with dental procedures). Patients should have dental evaluation before starting and avoid invasive dental procedures during therapy.", s: "CAT - Cancer Biology" },
  { q: "A nurse is caring for a patient who develops tumor lysis syndrome 24 hours after starting chemotherapy for Burkitt lymphoma. K+ is 6.8, Ca2+ 6.5, PO4 8.2, uric acid 12.8, and creatinine 3.4. Which intervention addresses the MOST immediately life-threatening abnormality?", o: ["Calcium gluconate for hyperkalemia (cardiac arrhythmia prevention)", "Rasburicase for uric acid", "Phosphate binder for hyperphosphatemia", "Fluid bolus for renal protection"], a: 0, r: "K+ 6.8 is immediately life-threatening (risk of fatal cardiac arrhythmia). Calcium gluconate stabilizes the myocardium FIRST. Then address K+ lowering (insulin/dextrose), uric acid (rasburicase), phosphate (binders), and renal protection (fluids).", s: "CAT - Cancer Biology" },
  { q: "A patient with cancer-induced superior vena cava syndrome arrives with severe facial/upper body edema and stridor. After elevating HOB and applying oxygen, the nurse should:", o: ["Administer diuretics", "Prepare for possible emergent airway intervention and notify oncology — stridor indicates potential airway compromise requiring immediate evaluation for stent placement or emergent radiation", "Wait for scheduled appointment", "Apply ice to reduce swelling"], a: 1, r: "SVC syndrome with stridor indicates potential airway compromise — this is an emergency. Endovascular stenting provides the fastest relief. Radiation therapy is also effective but takes days. Airway management takes priority.", s: "CAT - Cancer Biology" },
  { q: "A cancer patient with uncontrolled pain on morphine extended-release 60 mg q12h with breakthrough morphine IR 15 mg q4h PRN rates pain at 8/10. The patient has used 5 breakthrough doses in 24 hours. The nurse should:", o: ["Continue current regimen", "Calculate total 24-hour morphine use (120 mg ER + 75 mg IR = 195 mg), recommend increasing the baseline ER dose by 25-50%, and ensuring adequate breakthrough dosing", "Switch to non-opioid analgesics only", "Recommend hospice immediately"], a: 1, r: "When multiple breakthrough doses are needed, the baseline (around-the-clock) dose should be increased. Calculate total daily dose, increase ER by 25-50%, and ensure breakthrough dose is 10-15% of the new total daily dose.", s: "CAT - Cancer Biology" },

  // === CAT - ONCOLOGIC EMERGENCIES (15 questions) ===
  { q: "A patient undergoing induction chemotherapy for ALL develops oliguria, K+ 7.2, and peaked T waves on ECG 18 hours post-treatment. After administering calcium gluconate, the nurse should:", o: ["Wait for labs to normalize", "Administer insulin 10 units IV with D50W immediately, prepare for possible dialysis, and check if rasburicase was given prophylactically", "Give oral kayexalate only", "Increase IV fluids only"], a: 1, r: "K+ 7.2 with ECG changes is immediately life-threatening. After calcium gluconate (cardiac protection), insulin/dextrose provides fastest K+ lowering. Check if prophylactic measures (rasburicase, allopurinol) were given. Prepare for possible emergent dialysis.", s: "CAT - Oncologic Emergencies" },
  { q: "A patient with metastatic breast cancer to the spine reports progressive bilateral leg weakness over 2 days with difficulty walking and urinary retention. The nurse should:", o: ["Encourage ambulation", "Administer dexamethasone 10 mg IV STAT, obtain emergent MRI of entire spine, and contact radiation oncology/neurosurgery — this is spinal cord compression", "Schedule outpatient MRI next week", "Give NSAIDs for pain"], a: 1, r: "Progressive weakness + urinary retention = impending complete cord compression. Time is function — every hour without treatment increases permanent neurological damage. Dexamethasone reduces edema while emergent definitive treatment is arranged.", s: "CAT - Oncologic Emergencies" },
  { q: "A patient with SCLC presents with Na+ 118 mEq/L, serum osmolality 260 mOsm/kg, urine osmolality 550 mOsm/kg, and urine Na+ 40 mEq/L. The nurse recognizes:", o: ["Dehydration", "SIADH from ectopic ADH production — hyponatremia with inappropriately concentrated urine and euvolemia", "Diabetes insipidus", "Heart failure"], a: 1, r: "Classic SIADH: dilutional hyponatremia, low serum osmolality, inappropriately concentrated urine (should be dilute if serum is dilute), and elevated urine sodium. SCLC commonly produces ectopic ADH.", s: "CAT - Oncologic Emergencies" },
  { q: "A nurse is monitoring a patient with TLS prevention protocol. The current uric acid is 4.2 mg/dL (normal), but K+ is rising (5.6), PO4 is rising (6.8), and Ca2+ is falling (7.8). The nurse should:", o: ["Only monitor uric acid since it's normal", "Alert the provider — TLS is developing despite uric acid control; K+ and PO4 trends are concerning and Ca2+ is dropping secondary to hyperphosphatemia", "Continue current management without changes", "Discharge the patient"], a: 1, r: "TLS can develop even with adequate uric acid control. The electrolyte trends (rising K+, rising PO4, falling Ca2+) indicate developing TLS requiring intensification of management (increased hydration, phosphate binders, cardiac monitoring).", s: "CAT - Oncologic Emergencies" },
  { q: "A patient with lung cancer develops acute facial edema, dyspnea, and distended neck veins over 48 hours. CT shows a mediastinal mass compressing the SVC with intraluminal thrombus. The nurse anticipates:", o: ["Conservative management only", "Emergent SVC stent placement AND anticoagulation for the thrombus, with evaluation for radiation therapy or chemotherapy", "Surgery to remove the mass", "Observation"], a: 1, r: "SVC syndrome with thrombus requires both mechanical relief (stent) and anticoagulation. Stenting provides the fastest symptom relief (often within hours). Definitive tumor treatment (chemo/radiation) addresses the underlying cause.", s: "CAT - Oncologic Emergencies" },
  { q: "A patient at high risk for TLS is about to start chemotherapy. The nurse reviews the prevention orders and notes allopurinol 300 mg PO daily, D5W at 200 mL/hr, and potassium 20 mEq/L in the IV fluid. The nurse should:", o: ["Proceed with all orders", "Question the IV fluid — D5W is hypotonic (NS preferred) and potassium should NOT be added to TLS prevention fluids due to hyperkalemia risk", "Only question the allopurinol dose", "All orders are appropriate"], a: 1, r: "Multiple problems: NS (not D5W) should be used for TLS hydration. Potassium must NEVER be added to TLS fluids because hyperkalemia is a hallmark complication. The nurse's role in questioning inappropriate orders prevents harm.", s: "CAT - Oncologic Emergencies" },
  { q: "A cancer patient on chemotherapy develops simultaneous bleeding from IV sites, oozing from gum lines, and purple discoloration of fingers. Labs show PT 22 sec, aPTT 55 sec, fibrinogen 80 mg/dL, D-dimer 15,000, platelets 35,000. The nurse recognizes:", o: ["Vitamin K deficiency", "DIC — simultaneous clotting and bleeding with consumptive coagulopathy", "Heparin overdose", "Immune thrombocytopenia"], a: 1, r: "DIC shows paradoxical simultaneous bleeding AND clotting: elevated PT/aPTT (consumed factors), low fibrinogen (consumed), elevated D-dimer (fibrinolysis), low platelets (consumed). Treatment: address underlying cause, support with blood products.", s: "CAT - Oncologic Emergencies" },
  { q: "A nurse is caring for a patient with hypercalcemia of malignancy (Ca2+ 15.8 mg/dL) who is confused and oliguric. After starting aggressive NS hydration, the nurse anticipates:", o: ["Oral calcium supplements", "IV zoledronic acid AND calcitonin (bridge therapy) plus loop diuretic ONLY after adequate hydration", "Thiazide diuretic", "Vitamin D supplementation"], a: 1, r: "Severe hypercalcemia requires: aggressive hydration (restore volume first), then calcitonin for rapid onset (bridge), zoledronic acid for sustained effect. Loop diuretics only AFTER adequate hydration. NEVER thiazides (increase calcium).", s: "CAT - Oncologic Emergencies" },
  { q: "A patient with spinal cord compression from metastatic prostate cancer has been started on dexamethasone. After 24 hours, motor function continues to deteriorate. The nurse should:", o: ["Continue steroids and wait", "Escalate urgency — progressive neurological decline despite steroids requires emergent radiation therapy or surgical decompression within 24 hours", "Switch to a different steroid", "Discharge home on steroids"], a: 1, r: "Progressive neurological decline despite maximal steroids is an indication for emergent definitive treatment. Radiation therapy is standard; surgical decompression may be faster for rapid decline. Once paralysis occurs, it is usually permanent.", s: "CAT - Oncologic Emergencies" },
  { q: "A patient with TLS develops seizures. The nurse checks labs and finds Ca2+ 5.8 mg/dL and K+ 7.0 mEq/L. Which electrolyte abnormality is MOST likely causing the seizures?", o: ["Hyperkalemia", "Severe hypocalcemia (normal 8.5-10.5) — Ca2+ 5.8 can cause seizures, tetany, and cardiac arrhythmias", "Hyperphosphatemia directly", "Hyperuricemia"], a: 1, r: "While hyperkalemia causes cardiac arrhythmias, severe hypocalcemia (Ca2+ 5.8) directly causes neuromuscular excitability including seizures and tetany. Treat with IV calcium gluconate carefully (may precipitate with high phosphate levels).", s: "CAT - Oncologic Emergencies" },
  { q: "A nurse is prioritizing four oncology patients. Which requires FIRST assessment?", o: ["Patient with neutropenic fever (ANC 200, temp 38.5°C) diagnosed 30 minutes ago", "Patient with Ca2+ 12.5 with mild confusion on IV fluids", "Patient with stable spinal cord compression receiving dexamethasone", "Patient with resolved TLS on monitoring protocol"], a: 0, r: "Febrile neutropenia follows the 60-minute rule — antibiotics must be administered within 60 minutes. At 30 minutes since diagnosis, this patient is approaching the deadline. All other patients are currently stable on treatment.", s: "CAT - Oncologic Emergencies" },
  { q: "A patient undergoing TLS monitoring has blood drawn for uric acid. The nurse sends the sample at room temperature. The result comes back as 2.1 mg/dL (lower than expected for TLS). The nurse suspects:", o: ["Effective treatment", "Falsely low result — if the patient received rasburicase, the blood sample must be kept on ice because rasburicase continues to break down uric acid in the tube ex vivo", "Lab error unrelated to handling", "The patient doesn't have TLS"], a: 1, r: "Rasburicase continues to enzymatically degrade uric acid in blood samples at room temperature. Samples MUST be immediately placed on ice and transported on ice to the lab to prevent falsely low results.", s: "CAT - Oncologic Emergencies" },
  { q: "A patient with leukostasis (WBC 285,000 in AML) presents with headache, visual changes, and dyspnea. The nurse anticipates:", o: ["Standard chemotherapy", "Emergent leukapheresis to rapidly reduce WBC burden, aggressive hydration, and TLS prevention", "Observation", "Outpatient management"], a: 1, r: "Leukostasis (symptomatic hyperleukocytosis) is an oncologic emergency. The extremely elevated WBCs cause sludging in microvasculature. Leukapheresis rapidly reduces WBC count while chemotherapy takes effect.", s: "CAT - Oncologic Emergencies" },
  { q: "A patient with breast cancer develops sudden pleuritic chest pain, tachycardia, and JVD while on tamoxifen. D-dimer is elevated. The nurse suspects:", o: ["Pulmonary embolism — tamoxifen increases VTE risk", "Cardiac tamponade", "Pneumothorax", "Anxiety"], a: 0, r: "Tamoxifen increases venous thromboembolism risk 2-3 fold. Pleuritic chest pain, tachycardia, and elevated D-dimer strongly suggest PE. CT pulmonary angiography is the diagnostic study of choice.", s: "CAT - Oncologic Emergencies" },
  { q: "A patient with newly diagnosed lymphoma presents with bilateral lower extremity edema, ascites, and elevated LDH. CT shows massive retroperitoneal lymphadenopathy compressing the IVC. Before starting chemotherapy, the nurse ensures:", o: ["Standard pre-chemotherapy labs only", "Comprehensive TLS prevention: aggressive IV hydration (NS), allopurinol or rasburicase, electrolyte monitoring q4-6h, cardiac monitoring, and urine output monitoring — this patient has very high TLS risk", "No special precautions", "Oral hydration only"], a: 1, r: "Massive lymphadenopathy with elevated LDH indicates high tumor burden = very high TLS risk. Full prevention protocol must be in place BEFORE chemotherapy begins. The nurse ensures all prophylactic measures are implemented.", s: "CAT - Oncologic Emergencies" },

  // === CAT - NEUTROPENIC PRECAUTIONS (15 questions) ===
  { q: "A neutropenic patient (ANC 150) develops a temperature of 38.4°C at 2:00 AM. The night nurse calls the on-call provider who says to 'watch and recheck in 2 hours.' The nurse should:", o: ["Follow the order and recheck in 2 hours", "Advocate for immediate blood cultures and empiric antibiotics — the 60-minute rule is evidence-based and delays increase mortality, even at 2 AM", "Give acetaminophen and recheck", "Wait for the day team"], a: 1, r: "The 60-minute rule applies regardless of time of day. The nurse must advocate for the patient by citing evidence-based guidelines. If the on-call provider still refuses, escalate through the chain of command.", s: "CAT - Neutropenia" },
  { q: "A neutropenic patient's blood cultures grow gram-positive cocci in clusters from the central line. The nurse anticipates adding:", o: ["Cefepime (already being given)", "Vancomycin — gram-positive cocci in clusters (likely Staphylococcus) from a central line requires MRSA coverage", "Metronidazole", "Azithromycin"], a: 1, r: "Gram-positive cocci in clusters from a central line strongly suggests Staphylococcal catheter-related bloodstream infection. Vancomycin provides MRSA coverage. The central line may need removal if bacteremia persists.", s: "CAT - Neutropenia" },
  { q: "A patient on filgrastim after chemotherapy has an ANC that recovers from 200 to 8,500. The nurse notices the patient still has a fever despite 4 days of antibiotics and recovered counts. The nurse should:", o: ["Stop antibiotics since ANC recovered", "Evaluate for fungal infection — persistent fever despite ANC recovery and antibacterial therapy suggests invasive fungal disease; order galactomannan and CT chest", "Continue same antibiotics indefinitely", "Discharge with oral antibiotics"], a: 1, r: "Persistent fever despite ANC recovery and appropriate antibacterial therapy raises concern for invasive fungal infection (Aspergillus, Candida). CT chest may show halo sign. Serum galactomannan and beta-D-glucan help guide antifungal therapy.", s: "CAT - Neutropenia" },
  { q: "A nurse is planning care for a neutropenic patient who needs a central line dressing change, blood draw, and meal tray delivery. The CORRECT sequence is:", o: ["Any order is fine", "Hand hygiene → don PPE → dressing change with sterile technique → hand hygiene → blood draw → hand hygiene → deliver meal tray — clean procedures before potentially contaminating ones", "Meal first, then procedures", "Blood draw first"], a: 1, r: "In neutropenic patients, meticulous hand hygiene between tasks and performing the cleanest procedures first prevents cross-contamination. Central line care is the highest-risk procedure and should use maximum sterile barrier precautions.", s: "CAT - Neutropenia" },
  { q: "A neutropenic patient complains of perianal pain and tenderness. Examination reveals erythema but no fluctuance. The nurse understands:", o: ["This is a minor complaint", "Perianal infection in neutropenia can rapidly progress to sepsis — report immediately; avoid rectal procedures and start broad-spectrum antibiotics covering anaerobes", "Apply hemorrhoid cream", "Take a rectal temperature"], a: 1, r: "Perianal infections in neutropenic patients are life-threatening because they can rapidly progress to sepsis. Avoid ALL rectal manipulation (no thermometers, suppositories, or examinations). Start antibiotics with anaerobic coverage.", s: "CAT - Neutropenia" },
  { q: "A patient who received pegfilgrastim after chemotherapy develops severe bone pain (rated 8/10) in the pelvis and long bones. The nurse's approach should be:", o: ["Bone scan for metastatic disease", "Administer analgesics (acetaminophen, NSAIDs, or loratadine) — bone pain from marrow expansion is the expected side effect of G-CSF, not metastatic disease", "Stop pegfilgrastim immediately", "Order CT scan"], a: 1, r: "Bone pain from G-CSF-stimulated marrow expansion is common (20-30%). It is NOT a sign of disease progression. Manage with acetaminophen, NSAIDs, or interestingly, loratadine (which has shown effectiveness for G-CSF bone pain). Pain resolves as ANC recovers.", s: "CAT - Neutropenia" },
  { q: "A nurse is caring for a neutropenic patient with a central line who develops chills and hypotension immediately after a central line flush. The nurse suspects:", o: ["Vagal response", "Catheter-related bloodstream infection with possible biofilm release — draw paired cultures (central + peripheral) and start broad-spectrum antibiotics plus vancomycin", "Normal saline allergy", "Anxiety"], a: 1, r: "Chills and hypotension temporally related to central line flush suggest catheter-related bloodstream infection. The flush may dislodge biofilm or introduce bacteria. Draw paired cultures for differential time to positivity analysis.", s: "CAT - Neutropenia" },
  { q: "A patient with ANC of 100 has no fever but reports a sore throat and difficulty swallowing. Oral exam reveals white patches on the buccal mucosa. The nurse suspects:", o: ["Viral pharyngitis", "Oral candidiasis (thrush) — common in profound neutropenia; requires antifungal treatment (fluconazole)", "Normal finding", "Dehydration"], a: 1, r: "Oral candidiasis is very common in profoundly neutropenic patients. White patches that can be scraped off leaving erythematous base are characteristic. Treat with fluconazole (systemic, preferred over nystatin in neutropenia for better efficacy).", s: "CAT - Neutropenia" },
  { q: "A nurse reviews the medication list of a neutropenic patient and notices the provider ordered a live attenuated influenza vaccine (FluMist). The nurse should:", o: ["Administer as ordered", "Hold the vaccine and contact the provider — live vaccines are CONTRAINDICATED in immunosuppressed/neutropenic patients; use inactivated vaccine instead", "Give half the dose", "This is appropriate for neutropenic patients"], a: 1, r: "Live vaccines (LAIV, MMR, varicella, yellow fever) are absolutely contraindicated in immunosuppressed patients — the attenuated organisms can cause disease. Use inactivated influenza vaccine instead.", s: "CAT - Neutropenia" },
  { q: "A patient has been neutropenic (ANC <500) for 12 days with persistent fever despite broad-spectrum antibacterials and empiric voriconazole. CT chest shows new cavitary lesions. The nurse anticipates:", o: ["Continuing current management", "Possible invasive aspergillosis — consider bronchoalveolar lavage for galactomannan/culture, CT-guided biopsy, and adjustment of antifungal therapy based on species identification", "Tuberculosis treatment", "Discharge with oral antibiotics"], a: 1, r: "Cavitary lung lesions in prolonged neutropenia with persistent fever despite antifungals suggest possible breakthrough fungal infection or resistant organism. Tissue diagnosis guides species-specific antifungal adjustment.", s: "CAT - Neutropenia" },
  { q: "A nurse is educating a neutropenic patient about safe food handling at home. Which patient statement requires correction?", o: ["I will cook all meat to the proper temperature", "I will wash fruits and vegetables thoroughly before eating them raw", "I can eat raw sushi as long as it's from a reputable restaurant", "I will avoid soft cheeses made with unpasteurized milk"], a: 2, r: "Raw fish is NEVER safe for neutropenic patients regardless of restaurant quality. All meat, fish, and eggs must be fully cooked. Even reputable restaurants cannot guarantee absence of bacteria in raw preparations.", s: "CAT - Neutropenia" },
  { q: "A patient on febrile neutropenia protocol with cefepime for 5 days has defervesced and ANC is 650 (rising). The patient asks to go home. The nurse should:", o: ["Discharge immediately", "Assess if the patient meets criteria: ANC >500 AND afebrile 48+ hours; if ANC is rising but not yet sustained >500 for 48 hours, continue inpatient monitoring", "Continue IV antibiotics for 14 days regardless", "Switch to oral antibiotics and discharge"], a: 1, r: "Discharge criteria require both ANC recovery >500 AND afebrile for at least 48 hours. ANC 650 is improving but may not be sustained. Premature discharge risks breakthrough infection. Low-risk patients (MASCC ≥21) may transition to oral therapy earlier.", s: "CAT - Neutropenia" },
  { q: "A visitor arrives to see a neutropenic patient and mentions having a 'mild cold.' The nurse should:", o: ["Allow the visit with a mask", "Restrict the visit — even mild upper respiratory infections pose serious risk to neutropenic patients; the visitor should return when symptom-free", "Allow a brief visit", "It's fine since the visitor's illness is mild"], a: 1, r: "Any respiratory infection in a visitor can be devastating to a neutropenic patient. Even 'mild' colds involve viral shedding that could cause life-threatening infection. Restrict visits until the visitor is completely symptom-free.", s: "CAT - Neutropenia" },
  { q: "A neutropenic patient develops septic shock (BP 72/40 despite fluids, lactate 6.2, ANC 50). In addition to vasopressors and antibiotics, the nurse anticipates:", o: ["Standard sepsis care is sufficient", "Consider G-CSF to accelerate ANC recovery, ICU transfer for hemodynamic monitoring, and broadening antimicrobial coverage to include antifungal", "Reduce antibiotics to prevent resistance", "Observation only"], a: 1, r: "Neutropenic septic shock carries extremely high mortality. Management requires ICU-level care: aggressive fluid resuscitation, vasopressors, broad antimicrobials (antibacterial + antifungal), and G-CSF to accelerate neutrophil recovery.", s: "CAT - Neutropenia" },
  { q: "A nurse discovers that the neutropenic patient's roommate was just diagnosed with Clostridioides difficile. The nurse's IMMEDIATE action is:", o: ["Move the neutropenic patient to a private room immediately and implement contact precautions for the C. diff patient", "No action needed since C. diff is treated with antibiotics", "Give the neutropenic patient prophylactic vancomycin", "Wait for the infection control team"], a: 0, r: "C. diff spores can survive on surfaces for months. A neutropenic patient cannot afford any additional infection risk. Immediate separation is essential. The C. diff patient needs contact precautions with bleach-based cleaning.", s: "CAT - Neutropenia" },

  // === CAT - PEDIATRIC RESPIRATORY (15 questions) ===
  { q: "A 3-year-old with croup has stridor at rest but is alert and drinking. After dexamethasone 0.6 mg/kg and nebulized racemic epinephrine, the stridor resolves. The nurse should:", o: ["Discharge immediately", "Observe for 2-4 hours for rebound stridor — racemic epinephrine effect wears off in 2-4 hours and symptoms may return", "Admit to ICU", "Give another dose of epinephrine prophylactically"], a: 1, r: "Rebound stridor can occur as the vasoconstrictive effect of racemic epinephrine wears off. The 2-4 hour observation period is essential before considering discharge. If stridor recurs, another dose may be needed.", s: "CAT - Peds Respiratory" },
  { q: "A nurse is triaging two children in the ER. Child A has barky cough, hoarseness, and stridor with agitation only (croup). Child B has high fever, drooling, tripod positioning, and muffled voice. Which child needs FIRST assessment?", o: ["Child A — croup may worsen", "Child B — epiglottitis is immediately life-threatening with potential for complete airway obstruction; DO NOT examine throat", "Both can wait", "Neither is urgent"], a: 1, r: "Epiglottitis can rapidly progress to complete airway obstruction. Child B needs immediate assessment with emergency airway equipment at bedside. Do NOT examine the throat. Child A has mild croup (stridor only with agitation).", s: "CAT - Peds Respiratory" },
  { q: "A 6-week-old premature infant (born at 30 weeks) with RSV bronchiolitis has an apneic episode lasting 25 seconds with bradycardia to 70 bpm. The nurse's PRIORITY action is:", o: ["Stimulate the infant and provide bag-valve-mask ventilation if needed — apnea in premature infants with RSV is life-threatening", "Position for comfort only", "Administer albuterol", "Give caffeine citrate and observe"], a: 0, r: "Apnea in premature infants with RSV can be fatal. Tactile stimulation may restart breathing. If not, provide BVM ventilation. This infant needs continuous cardiorespiratory monitoring. ICU admission is likely needed.", s: "CAT - Peds Respiratory" },
  { q: "An infant with bronchiolitis has been admitted. The nursing student asks why we don't give bronchodilators. The BEST explanation is:", o: ["They are too expensive", "AAP evidence shows bronchodilators do not improve outcomes in bronchiolitis — the pathology is bronchiolar inflammation and mucus plugging, not bronchospasm like asthma", "They are never used in pediatrics", "Only the doctor can explain"], a: 1, r: "Bronchiolitis pathology (mucosal edema, mucus plugging, cellular debris) differs from asthma (bronchospasm). Bronchodilators target smooth muscle that is minimally developed in infant airways, explaining their lack of efficacy.", s: "CAT - Peds Respiratory" },
  { q: "A child with suspected epiglottitis is being prepared for OR intubation. The anesthesiologist is en route. While waiting, the child becomes increasingly anxious and the parent asks if the nurse can quickly look in the child's throat. The nurse should:", o: ["Briefly examine the throat to help the parent", "Firmly but gently decline — throat examination can trigger fatal laryngospasm; keep the child calm, allow comfort positioning, and prepare for emergency surgical airway if needed", "Use a tongue depressor for a quick look", "Have the parent look instead"], a: 1, r: "Any throat manipulation in epiglottitis can trigger complete airway obstruction. The nurse must refuse despite parental pressure, explain the danger simply, and keep the child calm. Have tracheostomy tray at bedside.", s: "CAT - Peds Respiratory" },
  { q: "A 4-month-old with RSV has deteriorating respiratory status: increasing retractions, head bobbing, grunting, and SpO2 87% on 2L nasal cannula. The nurse should:", o: ["Increase nasal cannula to 4L", "Prepare for escalation to high-flow nasal cannula (HFNC) or CPAP — this infant shows signs of impending respiratory failure", "Continue monitoring", "Suction and reassess in 1 hour"], a: 1, r: "Worsening respiratory distress with oxygen failure on standard delivery suggests need for HFNC or CPAP. Head bobbing and grunting are especially concerning signs in infants indicating significant respiratory distress.", s: "CAT - Peds Respiratory" },
  { q: "A nurse is advising parents about when to bring their child with croup to the ER. The MOST important teaching point is:", o: ["Come for any cough", "Seek emergency care if the child develops stridor at rest, severe breathing difficulty, drooling, high fever, or appears very ill — these may indicate severe croup or epiglottitis", "Never come to the ER for croup", "Only come during business hours"], a: 1, r: "Parents need to recognize red flags: stridor at rest (not just with crying), significant retractions, cyanosis, drooling (could indicate epiglottitis), high fever (>39°C unusual in croup — suggests bacterial process), and inability to drink.", s: "CAT - Peds Respiratory" },
  { q: "A child with croup is hospitalized. At 2 AM the child's cough and stridor seem worse. The nurse notes that the room air is very dry from the heating system. The nurse should:", o: ["Request cool mist treatment immediately", "Provide humidified oxygen if needed, comfort the child, and assess respiratory status systematically — note that cool mist is no longer recommended despite common belief", "Open the window for cold air", "Administer another dose of racemic epinephrine"], a: 1, r: "Despite historical practice, evidence does not support cool mist for croup. However, humidified oxygen delivery is appropriate if oxygen is needed. Focus on systematic assessment, comfort measures, and evidence-based interventions (dexamethasone, racemic epi for moderate-severe).", s: "CAT - Peds Respiratory" },
  { q: "A 2-month-old with bronchiolitis is having difficulty feeding (takes only 30% of usual volume) due to nasal congestion and tachypnea. The nurse should:", o: ["Force-feed with a bottle", "Suction the nose before feeds, offer smaller/more frequent feeds, and consider NG tube feeding or IV fluids if intake remains inadequate", "Stop all feeding until respiratory symptoms resolve", "Start solid foods"], a: 1, r: "Infants are obligate nose breathers — nasal congestion severely impairs feeding. Suctioning before feeds clears the airway. If oral intake is <50% or the infant shows signs of dehydration, NG feeding or IV fluids are needed.", s: "CAT - Peds Respiratory" },
  { q: "An infant is discharged from the hospital after bronchiolitis. The parents call the nurse advice line because the baby's breathing seems worse with the first feed at home. The nurse advises:", o: ["Come back to the ER immediately", "Suction the baby's nose with a bulb syringe BEFORE feeding, offer smaller volumes, and return to the ER if the baby has persistent tachypnea (>60), retractions, poor feeding, or decreased wet diapers", "Ignore it — it's normal", "Start albuterol at home"], a: 1, r: "Post-discharge bronchiolitis management includes nasal suctioning, small frequent feeds, and monitoring for red flags. Give concrete parameters (RR >60, retractions, <4 wet diapers in 24 hours) for when to return.", s: "CAT - Peds Respiratory" },
  { q: "A 12-month-old has been in the ER for 3 hours after receiving racemic epinephrine and dexamethasone for croup. Stridor has not returned, SpO2 is 97%, the child is playful and drinking well. The nurse assesses readiness for discharge:", o: ["Discharge is premature — observe 24 hours", "The child meets discharge criteria: >2 hours post-racemic epinephrine without rebound, dexamethasone given, tolerating oral fluids, and reliable family with return precautions", "More racemic epinephrine is needed", "Admit for observation"], a: 1, r: "Discharge criteria after croup treatment: adequate observation post-racemic epi (>2 hours), dexamethasone administered, drinking well, no stridor at rest, SpO2 >92%, reliable family who understands return precautions.", s: "CAT - Peds Respiratory" },
  { q: "A nurse is caring for two infants with RSV in the same room. One infant's condition is improving while the other is worsening. The nurse's MOST important infection control action is:", o: ["Shared equipment is fine since both have RSV", "Use separate equipment for each infant, perform hand hygiene between patients, and wear separate gowns/gloves for each — even with same diagnosis, viral loads and secondary infections differ", "No special precautions since they have the same virus", "Move them to private rooms"], a: 1, r: "Even though both have RSV, they may have different viral strains or secondary bacterial infections. Strict contact precautions between patients prevent cross-contamination. Dedicated equipment (stethoscopes, suction) for each patient.", s: "CAT - Peds Respiratory" },
  { q: "A child with a history of recurrent croup (4 episodes in 12 months) presents again. The nurse should consider:", o: ["This is normal — croup always recurs", "Evaluate for underlying airway abnormality — recurrent croup warrants ENT evaluation for subglottic stenosis, hemangioma, or other structural causes", "Continue treating as viral croup each time", "No further workup needed"], a: 1, r: "While occasional croup recurrence is common, frequent episodes (>2-3/year) warrant investigation for structural airway abnormalities: subglottic stenosis, laryngeal hemangioma, vascular ring, or gastroesophageal reflux with laryngeal irritation.", s: "CAT - Peds Respiratory" },
  { q: "A nurse is caring for a child with severe croup who received racemic epinephrine 45 minutes ago with good response. The child's mother asks if they can leave because the other child is at daycare. The nurse should:", o: ["Allow discharge with instructions", "Explain that the child must be observed for a minimum of 2 hours after racemic epinephrine because the medication effect can wear off and symptoms may return — leaving early puts the child at risk", "Let them go but call in 1 hour", "Agree if the parent signs AMA"], a: 1, r: "The nurse must clearly communicate the medical rationale: racemic epinephrine's effect lasts 2-4 hours. If rebound occurs during the drive home, the child could develop severe airway obstruction without access to emergency care.", s: "CAT - Peds Respiratory" },
  { q: "An infant hospitalized with bronchiolitis is on continuous pulse oximetry. SpO2 fluctuates between 89-94%. The nurse notices desaturations are brief and self-resolving. Current AAP guidelines would support:", o: ["Keeping the infant on continuous monitoring and supplemental oxygen for every desaturation", "Intermittent monitoring rather than continuous — brief self-resolving desaturations are common and continuous monitoring may prolong hospitalization unnecessarily", "Immediate intubation", "Increasing supplemental oxygen for all desaturations"], a: 1, r: "AAP guidelines suggest that continuous pulse oximetry may lead to unnecessary interventions and prolonged hospitalization. Brief self-resolving desaturations in otherwise well-appearing infants do not necessarily require intervention.", s: "CAT - Peds Respiratory" },

  // === CAT - PEDS FLUIDS (15 questions) ===
  { q: "A 15 kg child with severe dehydration (estimated 10%) arrives lethargic with HR 180, BP 70/40, and capillary refill 5 seconds. The nurse administers the first 20 mL/kg NS bolus (300 mL). After the bolus, HR is 165 and BP 78/45. The nurse should:", o: ["Wait and observe", "Repeat the 20 mL/kg bolus — inadequate response after first bolus requires repeat; reassess after each bolus up to 60 mL/kg total", "Start maintenance fluids", "Give oral rehydration"], a: 1, r: "Partial response (still tachycardic and hypotensive) after first bolus requires repeat bolus. Reassess after each 20 mL/kg up to 60 mL/kg total. If still hemodynamically unstable after 60 mL/kg, consider inotropes, blood products, or other causes.", s: "CAT - Peds Fluids" },
  { q: "A 6-month-old with gastroenteritis has Na+ 162 mEq/L. The nurse plans fluid management knowing that correction rate must not exceed:", o: ["1 mEq/L/hr", "0.5 mEq/L/hr or 10-12 mEq/L per 24 hours — rapid correction causes cerebral edema from idiogenic osmoles", "2 mEq/L/hr", "No rate limit"], a: 1, r: "Hypernatremic dehydration requires SLOW correction. Brain cells have accumulated idiogenic osmoles. Rapid lowering of Na+ causes water to rush into brain cells = cerebral edema, seizures, death. Correct over 48-72 hours.", s: "CAT - Peds Fluids" },
  { q: "A child in DKA has blood glucose 580 mg/dL, pH 7.10, and serum Na+ 128 mEq/L. After starting insulin and NS, the corrected sodium should be calculated. What is the corrected Na+ and what does a FALLING corrected Na+ indicate?", o: ["Corrected Na+ is approximately 135; falling corrected Na+ during treatment is normal", "Corrected Na+ is approximately 135 (add 1.6 mEq/L per 100 mg/dL glucose above 100); a FALLING corrected Na+ indicates risk of cerebral edema", "No correction needed", "Corrected Na+ is the same as measured"], a: 1, r: "Corrected Na+ = 128 + (1.6 × (580-100)/100) = 128 + 7.7 ≈ 135.7. A falling corrected Na+ during DKA treatment is a WARNING sign for cerebral edema — the leading cause of DKA death in children.", s: "CAT - Peds Fluids" },
  { q: "A 2-year-old with pyloric stenosis has been vomiting for 3 weeks. Labs show: Na+ 135, K+ 2.8, Cl- 88, HCO3- 35, pH 7.55. Before surgery, the nurse prioritizes:", o: ["Immediate surgery", "Correct the hypochloremic hypokalemic metabolic alkalosis with IV NS and potassium replacement — surgery should be delayed until electrolytes are corrected", "Start oral feeds", "Give sodium bicarbonate"], a: 1, r: "Pyloric stenosis causes classic hypochloremic hypokalemic metabolic alkalosis from HCl loss. Surgery is NOT an emergency — correct electrolyte imbalances FIRST (NS restores Cl-, add K+ after UOP confirmed). Operating on an alkalotic, hypokalemic child is dangerous.", s: "CAT - Peds Fluids" },
  { q: "A nurse is providing oral rehydration to a 10 kg infant with moderate dehydration. The infant vomits after receiving 30 mL. The nurse should:", o: ["Stop oral rehydration and start IV fluids", "Wait 10-15 minutes then restart ORS at 5 mL every 5 minutes by syringe — vomiting is not a contraindication to oral rehydration if volumes are small enough", "Give the full 30 mL again immediately", "Give antiemetic first"], a: 1, r: "Most children can be rehydrated orally even with mild vomiting if volumes are small enough. After vomiting, wait briefly then restart at 5 mL every 5 minutes. IV is reserved for intractable vomiting or severe dehydration.", s: "CAT - Peds Fluids" },
  { q: "A 5 kg premature infant is receiving maintenance IV fluids at the correct Holliday-Segar rate. A new nurse accidentally programs the pump at 10× the prescribed rate. The charge nurse discovers this after 2 hours. The infant now has tachypnea, periorbital edema, and a bulging fontanel. The PRIORITY actions are:", o: ["Continue fluids and monitor", "Immediately reduce fluid rate, elevate HOB, prepare for possible furosemide administration, assess respiratory status, and notify the provider — this is iatrogenic fluid overload", "Remove the IV completely", "No intervention needed"], a: 1, r: "Iatrogenic fluid overload in a premature infant is dangerous: risk of pulmonary edema, heart failure, and intraventricular hemorrhage. Immediately reduce rate, assess cardiopulmonary status, and prepare for diuretic therapy. File incident report.", s: "CAT - Peds Fluids" },
  { q: "A nurse is caring for a child in DKA receiving IV fluids and insulin. The child suddenly develops headache, vomiting, bradycardia, and altered consciousness. The nurse should:", o: ["Continue the protocol", "SUSPECT CEREBRAL EDEMA — elevate HOB, administer mannitol 0.5-1 g/kg IV or hypertonic saline, reduce IV fluid rate, and call for emergent CT and intubation readiness", "Give antiemetic", "This is normal DKA improvement"], a: 1, r: "These are classic signs of cerebral edema — the leading cause of DKA mortality in children. The Cushing response (bradycardia + altered consciousness) indicates rising ICP. Immediate osmotic therapy (mannitol or 3% saline) and fluid rate reduction are critical.", s: "CAT - Peds Fluids" },
  { q: "A 20 kg child needs maintenance fluids AND replacement of a 5% fluid deficit. Calculate the total first 24-hour fluid volume.", o: ["1500 mL maintenance only", "1500 mL maintenance + 1000 mL deficit (5% × 20 kg × 10) = 2500 mL total; give half the deficit in first 8 hours", "2000 mL total", "3000 mL total"], a: 1, r: "Maintenance (Holliday-Segar): 100×10 + 50×10 = 1500 mL/day. Deficit: 5% × 20 × 10 = 1000 mL. Total 2500 mL. For isotonic dehydration: give maintenance + half deficit in first 8 hours, remainder over next 16 hours.", s: "CAT - Peds Fluids" },
  { q: "A nurse notices a 6-month-old's weight has decreased from 7.5 kg (yesterday's known weight) to 6.9 kg. The infant has had diarrhea for 24 hours. The nurse calculates the percentage of dehydration as:", o: ["4%", "8% — (7.5-6.9)/7.5 × 100 = 8%, indicating moderate dehydration", "12%", "Unable to calculate"], a: 1, r: "% dehydration = (pre-illness weight - current weight) / pre-illness weight × 100 = (7.5-6.9)/7.5 × 100 = 8%. This is moderate dehydration in an infant (5-10% = moderate). This method is the most accurate when a recent pre-illness weight is available.", s: "CAT - Peds Fluids" },
  { q: "A nurse is reviewing the IV fluid order for a 3-month-old post-surgical patient: D5 0.2% NS at maintenance rate. The nurse should:", o: ["Administer as ordered", "Question the order — 0.2% NS is too hypotonic for a young infant and risks iatrogenic hyponatremia; isotonic maintenance (D5 0.45% NS or D5 NS) is now preferred", "Add potassium to make up for the low sodium", "This is the correct fluid"], a: 1, r: "Current evidence supports isotonic maintenance fluids (0.45-0.9% NS) in pediatric patients to prevent iatrogenic hyponatremia. Hypotonic fluids (0.2% NS) are especially dangerous in young infants due to immature renal concentrating ability.", s: "CAT - Peds Fluids" },
  { q: "A child with severe dehydration receives 3 boluses (60 mL/kg total) of NS. Vital signs improve but the child remains tachycardic with capillary refill of 4 seconds. The nurse considers:", o: ["Continue fluid boluses", "Evaluate for non-dehydration causes of shock (sepsis, cardiogenic, anaphylactic) — if pure dehydration, 60 mL/kg should show significant improvement", "Start maintenance fluids only", "This is adequate response"], a: 1, r: "After 60 mL/kg without adequate response, consider other causes of shock. Persistent poor perfusion may indicate sepsis (requiring antibiotics and vasopressors), cardiogenic shock (requiring inotropes — more fluid is harmful), or hemorrhagic shock (requiring blood).", s: "CAT - Peds Fluids" },
  { q: "A 4-year-old with gastroenteritis has mild dehydration (3-5%) and is tolerating small sips. The ER provider orders IV fluids. The nurse should:", o: ["Start IV immediately", "Advocate for oral rehydration therapy first — AAP recommends ORT as first-line for mild-moderate dehydration with intact ability to drink", "IV is always better", "Give cola and juice"], a: 1, r: "ORT is first-line for mild-moderate dehydration when the child can drink. It is as effective as IV therapy, less invasive, and less costly. The nurse should advocate for the evidence-based approach.", s: "CAT - Peds Fluids" },
  { q: "A nurse is calculating medications for a 12 kg child. The IV potassium order reads: KCl 40 mEq/L in D5 0.45% NS at 48 mL/hr. The nurse calculates this provides potassium at what rate and is it safe?", o: ["Cannot be calculated", "40 mEq/L × 0.048 L/hr = 1.92 mEq/hr; for 12 kg child this is 0.16 mEq/kg/hr — SAFE (max 0.5 mEq/kg/hr)", "This is too much potassium", "This provides 40 mEq/hr"], a: 1, r: "Calculate K+ delivery: 40 mEq per 1000 mL × 48 mL/hr = 1.92 mEq/hr ÷ 12 kg = 0.16 mEq/kg/hr. This is well within the safe range (max 0.5 mEq/kg/hr peripheral, max concentration 40 mEq/L peripheral).", s: "CAT - Peds Fluids" },
  { q: "A premature infant in the NICU has insensible water losses higher than a term infant. The nurse understands this is because:", o: ["They drink more", "Premature infants have thinner skin with higher transepidermal water loss, higher BSA:weight ratio, and immature stratum corneum", "They sweat more", "They have larger kidneys"], a: 1, r: "Premature infants have dramatically higher insensible losses: thin, immature skin (high transepidermal water loss), very high BSA:weight ratio, and limited ability to concentrate urine. Humidified isolettes and careful fluid calculations are essential.", s: "CAT - Peds Fluids" },
  { q: "A child with SIADH from meningitis has Na+ 122 mEq/L and is having seizures. The nurse anticipates:", o: ["Free water bolus", "3% hypertonic saline to raise Na+ by 4-6 mEq/L acutely to stop seizures, then fluid restriction and slow correction — rapid overcorrection risks osmotic demyelination", "Normal saline bolus only", "Oral sodium supplementation"], a: 1, r: "Symptomatic hyponatremia (seizures) requires emergent correction with 3% saline. Goal: raise Na+ 4-6 mEq/L acutely to stop seizures, then slow correction (max 8-10 mEq/L per 24 hours total) to prevent osmotic demyelination syndrome.", s: "CAT - Peds Fluids" },

  // === CAT - LOW CARDIAC OUTPUT PEDS (15 questions) ===
  { q: "A post-cardiac surgery infant has milrinone at maximum dose, epinephrine at 0.15 mcg/kg/min, and lactate has risen from 3 to 8 mmol/L over 4 hours. The nurse anticipates:", o: ["Continue current management", "ECMO deployment — this infant is failing maximal medical therapy and needs mechanical circulatory support", "Reduce inotropes to rest the heart", "Administer fluid bolus"], a: 1, r: "Rising lactate despite maximal inotropic support indicates refractory LCOS. ECMO provides temporary mechanical circulatory support, allowing the myocardium to rest and recover. Contact the ECMO team for rapid deployment.", s: "CAT - Peds Cardiac" },
  { q: "A nurse notices that a post-cardiac surgery infant's NIRS (cerebral near-infrared spectroscopy) has dropped from 68% to 45% over 30 minutes while other vitals remain stable. The nurse should:", o: ["Wait for vital sign changes before acting", "Alert the team immediately — declining cerebral NIRS indicates decreased brain oxygen delivery BEFORE vital signs deteriorate; this is an early warning of low cardiac output", "Increase oxygen delivery only", "This is a normal fluctuation"], a: 1, r: "NIRS provides early warning of tissue hypoxia before hemodynamic decompensation. A drop of >20% from baseline or absolute value <40-50% indicates inadequate cerebral perfusion and requires immediate investigation and intervention.", s: "CAT - Peds Cardiac" },
  { q: "A post-Norwood infant develops sudden cyanosis with SpO2 dropping from 80% to 55%. The nurse checks the Blalock-Taussig shunt for patency. What assessment finding would confirm shunt occlusion?", o: ["Continuous murmur present at the shunt site", "ABSENCE of the continuous murmur at the shunt site — loss of murmur indicates shunt occlusion", "Normal vital signs", "Improved perfusion"], a: 1, r: "The BT shunt produces a continuous murmur. Loss of this murmur with sudden desaturation indicates shunt thrombosis — a life-threatening emergency. Treatment includes heparin bolus and possible catheterization or surgical revision.", s: "CAT - Peds Cardiac" },
  { q: "A post-cardiac surgery child develops JET (junctional ectopic tachycardia) with a rate of 210 bpm. Cardiac output is declining. The nurse anticipates the treatment order of:", o: ["Digoxin", "Active cooling to 34-35°C, amiodarone, and atrial pacing at a rate faster than the JET to restore AV synchrony", "Adenosine push", "Cardioversion"], a: 1, r: "JET does not respond to cardioversion or adenosine. Treatment: 1) Active cooling slows the ectopic focus. 2) Amiodarone slows the rate. 3) Atrial pacing above the JET rate restores AV synchrony (atrial kick contributes 15-25% of CO).", s: "CAT - Peds Cardiac" },
  { q: "A post-cardiac surgery infant has chest tubes in place. The nurse notes that output was 3 mL/kg/hr for the first hour, then suddenly stops. Simultaneously, CVP rises from 8 to 18 mmHg, and BP drops. The nurse recognizes:", o: ["Normal cessation of drainage", "Cardiac tamponade — blood clot likely occluded the chest tube while blood continues accumulating in the pericardium", "Improved hemostasis", "Equipment malfunction only"], a: 1, r: "The classic triad: sudden cessation of drainage + rising CVP + falling BP = cardiac tamponade until proven otherwise. The tube must be evaluated (possible milking/stripping per protocol), and the surgeon notified for possible emergent sternotomy.", s: "CAT - Peds Cardiac" },
  { q: "A nurse is caring for a post-Fontan child. The child's SpO2 is 93% and CVP is elevated at 18 mmHg. The nurse understands that elevated CVP in Fontan circulation:", o: ["Is expected and harmless", "Indicates impaired pulmonary blood flow — in Fontan physiology, venous pressure drives pulmonary flow, and elevated CVP with low SpO2 suggests high pulmonary vascular resistance or pathway obstruction", "Means fluid overload only", "Is unrelated to oxygenation"], a: 1, r: "Fontan circulation has no subpulmonary ventricle — passive venous pressure drives pulmonary blood flow. Elevated CVP with low SpO2 means blood isn't flowing through the lungs efficiently. Causes include elevated PVR, pathway obstruction, or ventricular dysfunction.", s: "CAT - Peds Cardiac" },
  { q: "A post-cardiac surgery infant is on milrinone infusion. The nurse notes the infant's BP has dropped to 50/30 mmHg (below the 5th percentile for age). The nurse should:", o: ["Stop milrinone immediately", "Assess the clinical picture holistically — milrinone causes vasodilation; if perfusion markers are good (warm extremities, good UOP, clearing lactate) the low BP may be acceptable; if perfusion is poor, volume or vasopressor may be needed", "Bolus with albumin immediately", "This is always an emergency"], a: 1, r: "Milrinone is an inodilator — it reduces BP through vasodilation while improving forward flow. Assess perfusion markers (lactate, UOP, extremity temperature) rather than relying solely on BP. If perfusion is good despite low BP, the milrinone may be working correctly.", s: "CAT - Peds Cardiac" },
  { q: "A nurse is caring for a child with hypoplastic left heart syndrome (HLHS) who is pre-operative (awaiting Norwood). The infant's SpO2 is 95% on room air. Paradoxically, the nurse is CONCERNED because:", o: ["95% SpO2 is always good", "In HLHS, high SpO2 indicates excessive pulmonary blood flow (Qp:Qs too high), which means systemic perfusion is being 'stolen' — the infant may have inadequate systemic oxygen delivery despite high SpO2", "The pulse oximeter is wrong", "This is expected for HLHS"], a: 1, r: "In single ventricle physiology (HLHS), the balance between pulmonary (Qp) and systemic (Qs) blood flow is critical. SpO2 75-85% indicates balanced circulation. SpO2 >90% means too much blood is going to the lungs, reducing systemic perfusion.", s: "CAT - Peds Cardiac" },
  { q: "A post-cardiac surgery child has epicardial pacing wires. The heart rate drops to 45 bpm with poor perfusion. The nurse should:", o: ["Administer atropine only", "Activate the temporary pacemaker to provide emergency cardiac pacing — epicardial wires were placed intraoperatively for exactly this situation", "Wait for the cardiologist", "Increase IV fluids"], a: 1, r: "Epicardial pacing wires are placed prophylactically during cardiac surgery specifically for post-operative arrhythmias. The nurse should be competent in activating the external pacemaker. This provides immediate rate support while underlying causes are addressed.", s: "CAT - Peds Cardiac" },
  { q: "A post-cardiac surgery child develops high fever (39.8°C). Why is fever particularly dangerous in the LCOS risk window?", o: ["It indicates infection only", "Fever increases metabolic rate and myocardial oxygen demand by 10-12% per degree Celsius — the stunned myocardium cannot meet the increased demand, worsening LCOS", "Fever is protective", "It has no effect on cardiac output"], a: 1, r: "Each 1°C increase in temperature raises metabolic rate ~10-12% and increases myocardial oxygen demand. The stunned post-bypass myocardium cannot compensate, worsening the supply-demand mismatch and exacerbating LCOS.", s: "CAT - Peds Cardiac" },
  { q: "A nurse is weaning inotropes on a post-cardiac surgery child who has been stable for 24 hours. The milrinone is reduced from 0.5 to 0.375 mcg/kg/min. Within 2 hours, lactate rises from 1.2 to 3.5 and UOP decreases. The nurse should:", o: ["Continue weaning", "Return milrinone to the previous rate — the rising lactate and falling UOP indicate the myocardium is not ready for inotrope reduction", "Discontinue milrinone entirely", "Give a fluid bolus instead"], a: 1, r: "Rising lactate and falling UOP are the earliest indicators that cardiac output is insufficient. The myocardium is still dependent on inotropic support. Return to the previous effective dose and attempt weaning more slowly after further recovery.", s: "CAT - Peds Cardiac" },
  { q: "A nurse caring for a post-cardiac surgery infant calculates that the epinephrine is running at 0.2 mcg/kg/min. The attending asks to reduce it because 'the baby looks fine.' However, the nurse notes the lactate is 4.5 and UOP is 0.8 mL/kg/hr. The nurse should:", o: ["Reduce as ordered — the attending knows best", "Voice concern to the attending — clinical assessment may appear reassuring but objective measures (elevated lactate, borderline UOP) suggest ongoing inadequate perfusion requiring inotropic support", "Ignore the lab values", "Double the epinephrine dose"], a: 1, r: "The nurse has a responsibility to advocate based on objective data. 'Looking fine' is subjective, while lactate 4.5 and low UOP are objective evidence of inadequate tissue perfusion. Effective communication (SBAR) supports collaborative decision-making.", s: "CAT - Peds Cardiac" },
  { q: "A post-cardiac surgery infant develops acute desaturation, hypotension, and diminished breath sounds on the LEFT. Chest tubes are in situ but drainage has decreased. The nurse should:", o: ["Reposition the infant", "Suspect tension pneumothorax or significant pleural effusion — prepare for emergent chest tube evaluation/replacement and notify the surgeon immediately", "Increase FiO2 only", "Suction the endotracheal tube"], a: 1, r: "Unilateral diminished breath sounds with hemodynamic instability post-cardiac surgery suggests tension pneumothorax, hemothorax, or large pleural effusion. Existing chest tubes may be occluded or malpositioned. This requires immediate surgical evaluation.", s: "CAT - Peds Cardiac" },
  { q: "The family of a post-cardiac surgery child asks why the nurse keeps all the lights dim and groups care activities together. The BEST explanation is:", o: ["We're saving electricity", "Reducing stimulation lowers the baby's stress hormones and heart rate, which reduces the amount of work the recovering heart must do — clustering care gives longer rest periods between interventions", "It's hospital policy", "We prefer dim lighting"], a: 1, r: "Explain in family-friendly terms: each time the baby is disturbed, stress hormones increase heart rate and oxygen demand. The recovering heart needs to work as little as possible. Grouping care provides longer uninterrupted rest periods.", s: "CAT - Peds Cardiac" },
  { q: "A nurse identifies that a post-cardiac surgery child's mixed venous oxygen saturation (SvO2) has dropped from 70% to 50%. BP and HR are still normal. The nurse should:", o: ["Wait for vital sign changes", "Alert the team — falling SvO2 indicates the body is extracting more oxygen than normal, signaling inadequate cardiac output BEFORE vital signs change", "This is a normal finding", "Increase FiO2 only"], a: 1, r: "SvO2 dropping from 70% to 50% means tissue oxygen extraction has increased from 30% to 50% — the body is compensating for inadequate delivery. This is an early warning that precedes vital sign deterioration. Intervene now.", s: "CAT - Peds Cardiac" },

  // === CAT - PEDS SEIZURES (15 questions) ===
  { q: "A 14-month-old has a seizure lasting 8 minutes during a febrile illness. No IV access is available. The nurse's PRIORITY action is:", o: ["Attempt IV access repeatedly", "Administer IM midazolam 0.2 mg/kg — the RAMPART trial supports IM midazolam as equivalent to IV lorazepam when IV access is unavailable", "Wait for the seizure to stop", "Give oral medication"], a: 1, r: "At 8 minutes, this exceeds the 5-minute threshold for status epilepticus. IM midazolam is the evidence-based first-line when IV access is unavailable. Don't delay treatment by repeatedly attempting IV access.", s: "CAT - Peds Seizures" },
  { q: "A child has been seizing for 25 minutes despite two doses of lorazepam and one loading dose of fosphenytoin. The seizure continues. The nurse prepares for:", o: ["Another dose of lorazepam", "ICU transfer, continuous EEG monitoring, and initiation of a continuous infusion anesthetic (midazolam drip) with intubation and mechanical ventilation", "Observation", "Oral phenobarbital"], a: 1, r: "At 25+ minutes with failed first- and second-line agents, this is refractory status epilepticus. Requires ICU, continuous EEG, and anesthetic infusions (midazolam, propofol, or pentobarbital drip) with intubation for airway protection.", s: "CAT - Peds Seizures" },
  { q: "A nurse is caring for a 3-year-old who had a simple febrile seizure. The parents are extremely anxious and asking about daily anticonvulsant medication. The nurse's BEST response is:", o: ["The child needs daily medication immediately", "Simple febrile seizures do NOT require daily anticonvulsants and do NOT cause brain damage or lead to epilepsy — your child's risk of developing epilepsy is the same as any other child", "Never let the child have a fever", "The child should avoid all physical activity"], a: 1, r: "Parental anxiety after a febrile seizure is normal and intense. Evidence-based reassurance is a critical nursing intervention: simple febrile seizures are benign, do not cause brain damage, and do not increase epilepsy risk above the general population.", s: "CAT - Peds Seizures" },
  { q: "A seizing neonate has subtle seizures: eye deviation, lip smacking, and bicycling movements. The nurse obtains a fingerstick glucose of 28 mg/dL. The IMMEDIATE action is:", o: ["Regular feeding", "Administer D10W 2-5 mL/kg IV — neonatal hypoglycemia is the most rapidly reversible cause of seizures; D10W (NOT D50W) to avoid osmotic injury", "Administer D50W", "Wait for lab confirmation"], a: 1, r: "Neonatal hypoglycemia (glucose <45 mg/dL) requires immediate treatment with D10W (2-5 mL/kg). D50W and D25W are TOO concentrated for neonates — risk of rebound hypoglycemia, hyperglycemia, and intraventricular hemorrhage.", s: "CAT - Peds Seizures" },
  { q: "A 7-year-old with epilepsy on levetiracetam (Keppra) is brought to the clinic because of severe behavioral changes — aggression, irritability, and emotional outbursts. The parent asks if this is related to the medication. The nurse should:", o: ["Deny any connection", "Acknowledge that 'Keppra rage' is a well-known side effect affecting 10-20% of children, and recommend discussing medication adjustment or alternative with the neurologist", "Suggest increasing the dose", "Tell the parent it's a behavioral problem unrelated to medication"], a: 1, r: "Validate the parent's observation. Behavioral side effects of levetiracetam are well-documented. Options include dose adjustment, adding pyridoxine (B6), or switching to an alternative anticonvulsant. Never dismiss parental concerns.", s: "CAT - Peds Seizures" },
  { q: "A child presents with a first-time unprovoked seizure. Brain MRI shows a temporal lobe lesion. EEG shows focal epileptiform discharges. The nurse understands that this child:", o: ["Does not need treatment since it's a single seizure", "Has a high recurrence risk (>60%) due to structural abnormality and EEG findings — daily anticonvulsant therapy is likely indicated", "Should only be treated if a second seizure occurs", "Needs surgery immediately"], a: 1, r: "While treatment after a single unprovoked seizure is debated, structural lesion + epileptiform EEG = high recurrence risk (>60%). These risk factors justify initiating daily anticonvulsant therapy to prevent recurrence and potential injury.", s: "CAT - Peds Seizures" },
  { q: "A school nurse calls to report that a 10-year-old student had a seizure at school lasting 3 minutes that resolved spontaneously. The child has no seizure history. The nurse advises:", o: ["Send the child back to class", "Call 911 and parents — first seizure in a child always warrants emergent medical evaluation (stroke, tumor, infection, metabolic causes must be excluded)", "Give Tylenol and observe", "Document and wait for parents to notice"], a: 1, r: "A first-time unprovoked seizure in a child requires emergent evaluation. Serious causes (brain tumor, meningitis, vascular malformation, metabolic emergency) must be excluded. Call 911 and notify parents immediately.", s: "CAT - Peds Seizures" },
  { q: "A nurse is caring for a child post-status epilepticus who received lorazepam, fosphenytoin, and phenobarbital. The child is now postictal and has SpO2 88% with shallow respirations. The nurse should:", o: ["This is expected postictal breathing", "Intervene immediately — cumulative respiratory depression from multiple anticonvulsants; provide supplemental oxygen, position for airway patency, and prepare for possible assisted ventilation", "Give more anticonvulsants", "Wait for improvement"], a: 1, r: "Cumulative respiratory depression from multiple anticonvulsants (especially benzodiazepines + phenobarbital) can cause respiratory failure. SpO2 88% with shallow breathing requires immediate respiratory support. Have BVM and intubation equipment ready.", s: "CAT - Peds Seizures" },
  { q: "An 18-month-old has a complex febrile seizure (focal features, duration 20 minutes). Unlike a simple febrile seizure, the nurse should advocate for:", o: ["Same management as simple febrile seizure", "More thorough evaluation including possible LP (to rule out meningitis in this age group), EEG, and closer follow-up — complex features warrant further workup", "Daily anticonvulsant medication", "Immediate brain surgery"], a: 1, r: "Complex febrile seizures (focal, >15 min, recurrent in 24 hours) carry slightly higher epilepsy risk (2-4% vs 1%) and may mimic meningitis. LP should be strongly considered in children <12-18 months. EEG and follow-up are warranted.", s: "CAT - Peds Seizures" },
  { q: "A nurse is documenting a seizure and notes: the left arm began jerking first, then spread to involve the entire left side, then became generalized. This pattern is significant because:", o: ["It's not significant", "The focal onset with secondary generalization (Jacksonian march) localizes the seizure focus to the right motor cortex — this helps guide EEG placement and imaging", "All seizures start this way", "Only generalized seizures matter"], a: 1, r: "The 'Jacksonian march' (focal onset spreading along the motor cortex) localizes the seizure origin. Left-sided symptoms = right hemisphere focus. This information is valuable for the epileptologist in determining the seizure type and potential surgical candidacy.", s: "CAT - Peds Seizures" },
  { q: "A parent asks if their child with well-controlled epilepsy can participate in swimming. The nurse advises:", o: ["Absolutely no water activities", "Swimming is possible with precautions: always with a lifeguard and a designated 'seizure buddy' who knows the plan, no swimming alone, wear a life vest for open water, avoid diving", "No restrictions whatsoever", "Only in bathtubs"], a: 1, r: "Children with well-controlled epilepsy should be encouraged to participate in activities with appropriate safety precautions. Complete activity restriction affects quality of life and self-esteem. Individualized safety plans balance risk with normal childhood experiences.", s: "CAT - Peds Seizures" },
  { q: "A child on the ketogenic diet for refractory epilepsy becomes acutely ill with vomiting and lethargy. The nurse recognizes that standard treatment of vomiting with IV dextrose-containing fluids:", o: ["Is appropriate as always", "Must be used cautiously — dextrose can break ketosis and potentially trigger seizure recurrence; use NS initially and consult the ketogenic diet team", "Is contraindicated entirely", "Should include extra dextrose"], a: 1, r: "The ketogenic diet requires sustained ketosis for seizure control. IV dextrose rapidly breaks ketosis and may trigger seizures. Use NS initially and consult the ketogenic diet team for fluid management guidelines during illness.", s: "CAT - Peds Seizures" },
  { q: "A nurse is providing discharge teaching to parents of a child prescribed phenobarbital. Which instruction is MOST important?", o: ["Take only when seizures occur", "NEVER stop this medication suddenly — abrupt discontinuation can cause withdrawal seizures that are more severe than the original seizures; taper under medical supervision only", "You can adjust the dose based on symptoms", "There are no important instructions"], a: 1, r: "Abrupt discontinuation of phenobarbital (or any anticonvulsant) can trigger withdrawal seizures that may be more severe than the original epilepsy. Always taper under medical supervision over weeks to months.", s: "CAT - Peds Seizures" },
  { q: "A teenager with epilepsy is non-adherent to valproic acid. She reports she stops taking it because it makes her gain weight. The nurse's BEST approach is:", o: ["Insist she take it as prescribed", "Acknowledge the weight gain concern as valid, discuss alternative anticonvulsants with potentially fewer metabolic effects (levetiracetam, lamotrigine), and involve her in shared decision-making with the neurologist", "Tell her the seizures are worse than weight gain", "Switch to carbamazepine without consulting neurology"], a: 1, r: "Adolescent non-adherence requires empathetic approach. Validate concerns, involve the patient in decisions, and explore alternatives. Weight gain from VPA is a legitimate concern — several effective alternatives have neutral or favorable metabolic profiles.", s: "CAT - Peds Seizures" },
  { q: "A child has a generalized tonic-clonic seizure in the playroom. Multiple visitors are present and panicking. The nurse's FIRST three actions should be:", o: ["Clear the room of visitors first", "1) Note the time, 2) Clear the area around the child to prevent injury, 3) Position on side for airway protection — do NOT restrain, do NOT insert anything in the mouth", "1) Insert oral airway, 2) Restrain the child, 3) Call security", "1) Give Diastat immediately, 2) Call parents, 3) Take vitals"], a: 1, r: "Time the seizure (determines when to escalate treatment), protect from injury (clear objects), and maintain airway (recovery position). Never restrain or insert objects. Assign someone to time the seizure while you manage the airway.", s: "CAT - Peds Seizures" },

  // === CAT - WOUND HEALING (15 questions) ===
  { q: "A nurse discovers a post-surgical patient's abdominal wound has separated on day 6, revealing loops of bowel (evisceration). After covering with sterile saline-moistened towels and positioning supine with knees flexed, the nurse should:", o: ["Apply an abdominal binder", "Call the surgeon STAT for emergent OR return, keep the towels continuously moist, maintain NPO status, establish IV access, and continuously reassure the patient", "Push the bowel back and apply steri-strips", "Apply dry sterile dressing"], a: 1, r: "Evisceration is a surgical emergency. Never attempt to reinsert organs. Keep moist (never dry — desiccation causes tissue death). The patient needs emergent OR return. IV access for fluid/medication administration. The patient will be terrified — calm reassurance is essential.", s: "CAT - Wound Healing" },
  { q: "A diabetic patient has a non-healing foot ulcer despite 6 weeks of appropriate wound care. HbA1c is 9.8%. The nurse's MOST important recommendation is:", o: ["Change the wound dressing type", "Prioritize glycemic control — HbA1c 9.8% indicates poor glucose control that impairs neutrophil function, reduces tissue perfusion, and prevents healing regardless of wound care", "Hyperbaric oxygen therapy", "Surgical closure"], a: 1, r: "No wound care intervention will overcome the impaired healing caused by hyperglycemia. Blood glucose <180 mg/dL and HbA1c <7% are essential. Improving glucose control improves neutrophil function, perfusion, and collagen synthesis simultaneously.", s: "CAT - Wound Healing" },
  { q: "A patient on chronic prednisone 20 mg daily develops a pressure injury. The nurse advocates for:", o: ["Increasing the prednisone dose", "Adding vitamin A 10,000 IU daily to partially reverse the steroid-induced healing impairment", "Discontinuing prednisone immediately", "No specific intervention for steroid-related healing impairment"], a: 1, r: "Vitamin A (10,000 IU/day) partially restores macrophage function, collagen synthesis, and epithelialization suppressed by chronic corticosteroids. This is a specific, evidence-based intervention for steroid-impaired wound healing.", s: "CAT - Wound Healing" },
  { q: "A nurse is choosing a wound dressing for a stage 3 pressure injury with moderate exudate and a red granulating base. The BEST choice is:", o: ["Dry gauze packing changed BID", "Foam dressing — absorbs moderate exudate while maintaining optimal moisture for the granulating wound bed", "Hydrogel", "No dressing needed"], a: 1, r: "Match dressing to wound needs: foam absorbs moderate exudate (too wet for hydrogel, too moist for dry gauze). The granulating base should be protected (not debrided). Foam maintains optimal moisture without maceration.", s: "CAT - Wound Healing" },
  { q: "A patient with a chronic wound has a prealbumin of 8 mg/dL (normal 15-35). The nurse's PRIORITY intervention is:", o: ["Continue current wound care without dietary changes", "Initiate nutrition consult for protein supplementation (1.25-1.5 g/kg/day) with vitamins C and zinc — severe protein-calorie malnutrition is preventing healing", "Start TPN immediately", "Increase wound dressing changes"], a: 1, r: "Prealbumin 8 mg/dL indicates severe malnutrition. No wound care intervention will succeed without correcting the nutritional deficit. Protein, vitamin C, and zinc are essential building blocks for collagen synthesis and immune function.", s: "CAT - Wound Healing" },
  { q: "A wound VAC dressing has a persistent air leak (the canister does not achieve target pressure). The nurse should:", o: ["Increase the suction pressure", "Inspect all seal edges for breach, ensure the drape is intact without wrinkles, check tubing connections, and apply additional drape if needed — the system requires an airtight seal", "Remove the wound VAC", "Ignore the alarm"], a: 1, r: "NPWT requires an airtight seal to maintain negative pressure. Systematically check: drape integrity, drape-skin interface (creases, hair, moisture), tubing connections, and canister placement. Reapply drape as needed. Do NOT simply increase pressure.", s: "CAT - Wound Healing" },
  { q: "A patient with a clean granulating wound asks why the nurse uses normal saline instead of hydrogen peroxide for cleaning. The BEST explanation is:", o: ["Hydrogen peroxide is more expensive", "Hydrogen peroxide destroys healthy cells (fibroblasts) needed for healing — normal saline cleans without damaging the cells that are building new tissue", "No difference between them", "We ran out of hydrogen peroxide"], a: 1, r: "Explain in patient-friendly terms: hydrogen peroxide kills the 'worker cells' (fibroblasts) that are building new tissue. NS cleans the wound without harming these cells. Use evidence to guide practice over tradition.", s: "CAT - Wound Healing" },
  { q: "A nurse assesses a wound and documents: 3 cm × 2 cm × 0.5 cm, 90% red granulation tissue, 10% yellow slough at 6 o'clock position, moderate serosanguineous drainage, no odor, and 1.5 cm undermining at 3-6 o'clock. This wound is:", o: ["Infected and deteriorating", "Predominantly healing well with a small area requiring gentle debridement — the red granulation indicates proliferative phase while the focal slough and undermining need attention", "Completely healed", "Needs surgical closure"], a: 1, r: "Comprehensive wound assessment guides individualized care. 90% granulation is positive. The 10% slough at 6 o'clock needs gentle debridement. Undermining needs packing. Serosanguineous drainage without odor suggests no infection.", s: "CAT - Wound Healing" },
  { q: "A patient with arterial insufficiency has a lower extremity wound. The nurse measures an ankle-brachial index (ABI) of 0.45. This is significant because:", o: ["ABI 0.45 is normal", "Severe arterial insufficiency (ABI <0.5) means the wound lacks adequate blood supply to heal — compression therapy is CONTRAINDICATED and vascular surgery consultation is needed", "Compression bandaging will help", "No impact on wound care"], a: 1, r: "ABI <0.5 = severe peripheral arterial disease. The wound cannot heal without revascularization. Compression therapy (used for venous ulcers) is CONTRAINDICATED as it further reduces arterial flow. Vascular surgery consultation is essential.", s: "CAT - Wound Healing" },
  { q: "A nurse notices a Stage 2 pressure injury on a patient who was admitted 48 hours ago with intact skin. The nurse should:", o: ["Do nothing — it's only Stage 2", "Document as hospital-acquired pressure injury (HAPI), implement prevention measures, adjust the care plan, report per institutional policy, and investigate contributing factors", "Blame the previous shift", "Document as present on admission"], a: 1, r: "HAPI documentation is important for quality improvement, reimbursement (hospitals may not be reimbursed for hospital-acquired conditions), and patient safety. Investigate contributing factors (missed repositioning, inadequate nutrition, moisture).", s: "CAT - Wound Healing" },
  { q: "A home health nurse visits a patient whose wound has been treated with a honey-based dressing by the patient's spouse. The wound appears improved with clean granulation. The nurse should:", o: ["Remove the honey immediately", "Acknowledge that medical-grade honey (Medihoney) has evidence-based antimicrobial properties; if they're using non-medical honey, educate about the difference and transition to medical-grade", "Continue with table honey", "Report the spouse for practicing medicine"], a: 1, r: "Medical-grade honey (Manuka/Medihoney) has evidence-based wound healing properties: antimicrobial, anti-inflammatory, and promotes autolytic debridement. Distinguish from table honey (not sterile). Transition to medical-grade and maintain therapeutic relationship.", s: "CAT - Wound Healing" },
  { q: "A nurse is deciding between sharp debridement and autolytic debridement for a wound with 40% yellow slough. The patient is on warfarin with INR 3.5. The nurse should:", o: ["Proceed with sharp debridement", "Use autolytic debridement (moisture-retentive dressing) — the elevated INR makes sharp debridement risky due to bleeding; enzymatic debridement is another option", "No debridement needed", "Surgical debridement only"], a: 1, r: "Sharp debridement carries bleeding risk in anticoagulated patients (INR 3.5 is supratherapeutic). Autolytic debridement (hydrogel or moisture-retentive dressing) uses the body's own enzymes safely. Enzymatic debridement (collagenase) is another option.", s: "CAT - Wound Healing" },
  { q: "A nurse notes that a patient's wound has hypergranulation (granulation tissue extending above the wound surface). This prevents:", o: ["Nothing — it's a sign of good healing", "Epithelial cell migration across the wound surface — the raised tissue creates a barrier that must be treated before the wound can close", "Blood flow to the wound", "Infection control"], a: 1, r: "Hypergranulation creates a physical barrier to epithelial migration. Treatment includes silver nitrate cauterization, topical corticosteroid, or foam dressing with gentle pressure. Identify and address the cause (infection, moisture imbalance, foreign body).", s: "CAT - Wound Healing" },
  { q: "A patient asks why their wound dehisced on day 5 after surgery. The nurse explains that:", o: ["It's random and unpredictable", "Days 5-8 are highest risk because the wound is transitioning from inflammatory to proliferative phase with minimal tensile strength — risk factors include obesity, coughing, poor nutrition, and infection", "Surgical technique was wrong", "This never happens"], a: 1, r: "Day 5-8 is the 'danger zone' — the wound has left the inflammatory phase but hasn't developed significant collagen strength. Combined with mechanical stress (coughing, straining) and risk factors, dehiscence risk peaks.", s: "CAT - Wound Healing" },
  { q: "A nurse is managing a patient with a chronic venous leg ulcer. The ABI is 0.85 (acceptable). The cornerstone of treatment is:", o: ["Elevation only", "Compression therapy (multi-layer compression bandaging) — venous ulcers require sustained compression to counteract venous hypertension and promote healing", "Arterial bypass", "Antibiotic therapy alone"], a: 1, r: "Venous ulcers result from venous hypertension. Compression therapy (30-40 mmHg) is the cornerstone: it improves venous return, reduces edema, and promotes healing. ABI must be >0.5 (ideally >0.8) to safely apply compression.", s: "CAT - Wound Healing" },

  // === CAT - PRESSURE INJURIES (15 questions) ===
  { q: "A dark-skinned patient is admitted and the nurse notices a purple, non-blanchable area over the sacrum that feels boggy and warmer than surrounding tissue. This is MOST likely:", o: ["A normal skin variation", "Deep tissue pressure injury (DTPI) — purple discoloration with bogginess indicates underlying soft tissue damage that may evolve to full-thickness injury", "Stage 1 pressure injury", "A bruise from a fall"], a: 1, r: "In darker skin, DTPI presents as purple/maroon discoloration that is non-blanchable. The boggy, warm quality confirms underlying tissue damage. DTI may rapidly evolve to Stage 3 or 4, or may resolve. Close monitoring is essential.", s: "CAT - Pressure Injuries" },
  { q: "A nurse discovers that a patient's pulse oximeter has been on the same finger for 48 hours without being moved. The skin underneath shows a circular non-blanchable red area. This is classified as:", o: ["Stage 1 from dehydration", "Medical device-related pressure injury (MDRPI) — Stage 1; the shape/location correspond to the medical device", "Normal skin reaction to adhesive", "Contact dermatitis"], a: 1, r: "Medical device-related pressure injuries are classified using the same staging system but documented as MDRPI. The shape/location matches the device. Prevention: inspect under devices every shift and reposition devices regularly.", s: "CAT - Pressure Injuries" },
  { q: "A patient with a Stage 4 sacral pressure injury has exposed bone visible at the wound base. The wound has been present for 6 months with minimal healing despite appropriate wound care. The nurse suspects:", o: ["Inadequate wound care", "Osteomyelitis — non-healing wound with exposed bone for extended period; order MRI and probe-to-bone test", "Normal healing timeline", "Vitamin deficiency only"], a: 1, r: "Non-healing Stage 4 with chronically exposed bone strongly suggests osteomyelitis. Probe-to-bone test (if a probe touches bone through the wound, positive predictive value ~89%) and MRI are diagnostic. Treatment requires prolonged antibiotics and possible bone debridement.", s: "CAT - Pressure Injuries" },
  { q: "A nurse is caring for a patient on a specialty air-fluidized bed for a Stage 4 pressure injury. The nursing assistant asks why repositioning is still necessary since the patient is on a specialty surface. The nurse explains:", o: ["Repositioning is not needed on specialty surfaces", "Specialty surfaces REDUCE but do not ELIMINATE pressure — repositioning remains essential because no surface completely removes interface pressure below capillary closing pressure for all body areas", "The bed does the repositioning automatically", "Repositioning is optional on air-fluidized beds"], a: 1, r: "Even the most advanced support surfaces cannot completely eliminate pressure at all interface points. They redistribute pressure but do not replace repositioning. Continue every-2-hour repositioning schedule even on specialty surfaces.", s: "CAT - Pressure Injuries" },
  { q: "A hospice patient has a new Kennedy terminal ulcer on the sacrum — a pear-shaped, rapidly developing wound. The family is distressed and asks if the nursing home 'caused this.' The nurse should:", o: ["Blame the facility", "Explain that Kennedy terminal ulcers are associated with the dying process and multiorgan failure — skin breakdown can be unavoidable at end of life despite excellent care, and document accordingly", "Agree it was negligence", "Ignore the family's concern"], a: 1, r: "Kennedy terminal ulcers are a recognized phenomenon occurring near death as skin becomes the first organ to fail. Compassionate education helps families understand this is not negligence. Document the clinical context and unavoidable nature.", s: "CAT - Pressure Injuries" },
  { q: "A nurse assesses a wound that was previously documented as 'Stage 3.' Today the wound bed shows 100% clean red granulation tissue and the wound has decreased in size. The nurse documents:", o: ["Stage 2 (reverse staging)", "Stage 3, healing — wound is improving with clean granulation; NEVER reverse stage because the original depth of tissue loss doesn't change", "Stage 1", "Unstageable"], a: 1, r: "Never reverse stage. A healing Stage 3 fills with granulation tissue, not original subcutaneous tissue. Document as 'Stage 3, healing' with description of wound bed (100% granulation), decreasing measurements, and improving characteristics.", s: "CAT - Pressure Injuries" },
  { q: "A nurse is caring for a ventilated ICU patient with an endotracheal tube secured with a commercial holder. During oral care, the nurse notices a Stage 2 pressure injury on the lip. The nurse should:", o: ["Ignore it — it's just a small sore", "Document as a medical device-related pressure injury, reposition the ETT and holder to offload the injured area, apply appropriate dressing, and notify the provider and wound care team", "Remove the ETT to heal the sore", "Apply petroleum jelly and continue"], a: 1, r: "ETT-related lip injuries are MDRPI and should be formally documented. Reposition the tube (alternate corner of mouth), use protective padding, and apply appropriate dressing. This is a quality indicator and should be reported per institutional policy.", s: "CAT - Pressure Injuries" },
  { q: "A Braden score of 8 (very high risk) is obtained for a new ICU admission. The nurse implements ALL of the following EXCEPT:", o: ["Specialty pressure redistribution surface (low-air-loss mattress)", "Repositioning every 2 hours with documentation", "Heel elevation with pillows under calves", "Massage of reddened bony prominences to improve circulation"], a: 3, r: "NEVER massage reddened bony prominences — this causes additional tissue damage by creating shear forces in already compromised tissue. All other interventions are appropriate for very high-risk patients.", s: "CAT - Pressure Injuries" },
  { q: "A nurse identifies periwound maceration (white, waterlogged skin) around a pressure injury. This indicates:", o: ["Good moisture balance", "Excessive moisture from wound drainage or incontinence damaging the periwound skin — requires moisture barrier and possibly more absorptive dressing", "Healthy healing", "Normal finding"], a: 1, r: "Maceration weakens the epidermis and expands the wound. Address: apply barrier cream/paste to periwound skin, use more absorptive dressing (alginate, foam), manage incontinence, and consider pouching system if drainage is heavy.", s: "CAT - Pressure Injuries" },
  { q: "A patient with a spinal cord injury at T4 cannot sense pain below the level of injury. The Braden sensory perception domain should be scored as:", o: ["4 (no impairment)", "3 (slightly limited)", "1 (completely limited — no ability to feel pain/pressure below T4)", "2 (very limited)"], a: 2, r: "Complete loss of sensory perception below the injury level = score of 1. This patient cannot feel pressure or pain in the sacral, ischial, and heel areas, significantly increasing PI risk. Sensory perception is the most critical Braden domain.", s: "CAT - Pressure Injuries" },
  { q: "A nurse is evaluating a wound documented as 'unstageable due to eschar.' The eschar on the sacrum is stable, dry, and intact. The eschar on the heel is also stable, dry, and intact. The nurse should:", o: ["Debride both wounds", "Leave the heel eschar intact (biological cover) but consult wound care about the sacral eschar — stable heel eschar should NOT be debrided, but sacral eschar management depends on clinical context", "Debride neither", "Apply wet-to-dry dressings to both"], a: 1, r: "Stable, dry, intact eschar on heels specifically should NOT be debrided — it serves as the body's natural biological dressing. Sacral eschar management is more nuanced and depends on the clinical situation (presence of infection, fluctuance, patient goals of care).", s: "CAT - Pressure Injuries" },
  { q: "A patient's family member is providing skin care and uses a hair dryer on a hot setting to 'dry the skin' after incontinence episodes. The nurse should:", o: ["Encourage this technique", "Educate that heat damages fragile skin and increases PI risk — teach proper cleansing with pH-balanced cleanser, patting dry (not rubbing), and applying dimethicone-based barrier cream", "Suggest a hotter setting", "This is appropriate care"], a: 1, r: "Hot air damages already compromised skin. Proper perineal care: gentle cleansing with pH-balanced cleanser (not soap), pat dry (don't rub), apply barrier cream (dimethicone-based), and change absorbent products promptly.", s: "CAT - Pressure Injuries" },
  { q: "A quality improvement nurse is reviewing PI data. The unit's HAPI rate has not improved despite repositioning protocols. The NEXT step should be:", o: ["Increase repositioning to every hour for everyone", "Perform a root cause analysis — assess compliance with repositioning, nutrition optimization, moisture management, support surface selection, and staff education; identify system barriers", "Accept the rate as inevitable", "Purchase more expensive mattresses"], a: 1, r: "Root cause analysis identifies WHY protocols aren't working: compliance barriers (staffing, documentation), inadequate nutrition assessment, inappropriate support surface selection, moisture management gaps, or education needs. Address system issues, not just individual behavior.", s: "CAT - Pressure Injuries" },
  { q: "A patient with a Stage 3 trochanteric pressure injury is scheduled for a total hip replacement on the same side. The nurse's MOST important preoperative communication is:", o: ["No special communication needed", "Alert the surgical team about the wound location — the incision and positioning during surgery must account for the existing wound to prevent further tissue damage and infection", "Cancel the surgery", "The wound will heal after surgery"], a: 1, r: "The surgical team needs to know about the existing wound for incision planning, positioning during surgery (avoid pressure on the wound), infection risk assessment, and post-operative wound management coordination.", s: "CAT - Pressure Injuries" },
  { q: "A nurse receives a patient from the OR after a 9-hour surgery. The patient was positioned prone on the operating table. The nurse should IMMEDIATELY assess:", o: ["Only the surgical site", "Pressure areas from OR positioning: face (forehead, chin, cheeks), chest, iliac crests, knees, and dorsal feet — prolonged OR positioning is a major risk factor for intraoperative HAPI", "Only the sacrum", "Only heels"], a: 1, r: "Prolonged OR time (>2 hours) is a significant PI risk factor. Prone positioning creates unique pressure points. Assess ALL contact areas immediately — intraoperative PIs may not become apparent for 24-72 hours. Document baseline skin assessment.", s: "CAT - Pressure Injuries" },

  // === CAT - SKIN CANCER (15 questions) ===
  { q: "A patient shows the nurse a mole that has recently changed: one half is larger than the other, the borders are irregular, it has multiple colors (brown, black, and red), it's 8 mm in diameter, and it has grown over the past 2 months. The nurse should:", o: ["Reassure the patient it's benign", "Recommend URGENT dermatologic evaluation — this lesion meets ALL ABCDE criteria for melanoma and the recent evolution (E) is especially concerning", "Apply sunscreen to the mole", "Monitor at next annual exam"], a: 1, r: "Meeting all 5 ABCDE criteria with recent change makes melanoma highly likely. Evolution (E) is the most sensitive criterion. Urgency is needed because melanoma prognosis worsens with increasing Breslow depth — early excision saves lives.", s: "CAT - Skin Cancer" },
  { q: "A patient on pembrolizumab for metastatic melanoma develops severe diarrhea (8 episodes/day) with blood. The nurse suspects:", o: ["Food poisoning", "Immune-related colitis from checkpoint inhibitor therapy — requires IMMEDIATE reporting, possible colonoscopy, and high-dose corticosteroids", "IBS exacerbation", "Viral gastroenteritis"], a: 1, r: "Severe diarrhea with blood on checkpoint inhibitors = immune-related colitis until proven otherwise. Grade 3-4 colitis requires holding immunotherapy, IV corticosteroids, and possible infliximab. Can progress to perforation if untreated.", s: "CAT - Skin Cancer" },
  { q: "An organ transplant recipient presents with a rapidly growing, crusted nodule on the hand. Given the 65x increased SCC risk, the nurse prioritizes:", o: ["Annual dermatology visit", "Urgent biopsy and dermatologic evaluation — SCC in immunosuppressed patients is more aggressive with higher metastatic potential requiring prompt treatment", "Topical steroid application", "Observation for 6 months"], a: 1, r: "SCC in immunosuppressed patients behaves more aggressively with higher metastatic rates (10-20% vs 3-5%). Any new or changing lesion requires urgent evaluation. These patients need dermatologic screening every 6-12 months.", s: "CAT - Skin Cancer" },
  { q: "A nurse is educating a patient about topical 5-fluorouracil (Efudex) for actinic keratoses. The patient calls after 2 weeks reporting the treated area is 'red, raw, and ugly.' The nurse should:", o: ["Tell the patient to stop the medication", "Reassure that the severe inflammatory reaction is the EXPECTED therapeutic response — the medication is selectively destroying pre-cancerous cells; encourage continuation through the treatment course", "Prescribe antibiotics for infection", "Apply steroids to reduce inflammation"], a: 1, r: "Patient education before starting 5-FU is critical. The inflammatory response IS the treatment — it confirms the medication is working. Premature discontinuation leads to incomplete treatment. Provide anticipatory guidance and support.", s: "CAT - Skin Cancer" },
  { q: "A patient with melanoma (Breslow depth 1.8 mm) has a positive sentinel lymph node. The nurse anticipates the next steps will include:", o: ["No further treatment needed", "Possible completion lymph node dissection AND adjuvant systemic therapy (checkpoint inhibitor or BRAF/MEK inhibitors if BRAF-mutated) to reduce recurrence risk", "Radiation therapy only", "Topical treatment only"], a: 1, r: "Positive sentinel node (Stage III) requires: possible completion lymph node dissection (debated), adjuvant systemic therapy (1 year of pembrolizumab/nivolumab, or BRAF/MEK for BRAF-mutated), and close surveillance. The 5-year survival drops significantly with nodal involvement.", s: "CAT - Skin Cancer" },
  { q: "A patient notices a dark longitudinal streak developing under their toenail. There is no history of trauma. The nurse should:", o: ["It's probably a fungal infection", "Recommend dermatologic evaluation — subungual melanoma presents as longitudinal melanonychia; Hutchinson sign (pigment extending to the nail fold) is especially concerning", "Apply antifungal medication", "Ignore it — it's a normal aging change"], a: 1, r: "Acral lentiginous melanoma (under nails) is the most common melanoma in dark-skinned individuals and is often diagnosed late. Hutchinson sign (pigment in the nail fold) is a red flag. Any new or changing nail streak without trauma needs dermatologic evaluation.", s: "CAT - Skin Cancer" },
  { q: "A nurse is providing sun protection education to the parents of a fair-skinned child. The MOST important message is:", o: ["One sunburn doesn't matter", "Blistering sunburns before age 18 are the strongest modifiable risk factor for melanoma — protecting children from UV damage is the single most effective melanoma prevention strategy", "Sunscreen is only needed at the beach", "Tanning is fine if gradual"], a: 1, r: "Childhood UV exposure has the strongest impact on lifetime melanoma risk. Key messages: avoid sun 10 AM-4 PM, use SPF 30+ broad-spectrum sunscreen, protective clothing and hats, no tanning beds ever, and recognize that there is NO safe tan.", s: "CAT - Skin Cancer" },
  { q: "A patient is diagnosed with nodular melanoma. The nurse understands this subtype is particularly dangerous because:", o: ["It is the most common type", "It has VERTICAL growth from onset (no radial growth phase) and is often diagnosed at greater Breslow depth — it appears as a dark, rapidly growing, dome-shaped nodule", "It only occurs on sun-exposed areas", "It has the best prognosis"], a: 1, r: "Nodular melanoma (15-30% of melanomas) grows vertically from the start, bypassing the radial growth phase. This means it invades deeply before being detected, leading to diagnosis at greater Breslow depth with worse prognosis.", s: "CAT - Skin Cancer" },
  { q: "A patient with history of multiple basal cell carcinomas is offered vismodegib (Hedgehog pathway inhibitor). The nurse educates about this medication:", o: ["It's a topical cream", "It's an oral targeted therapy for advanced/recurrent BCC that inhibits the Hedgehog signaling pathway; side effects include muscle spasms, alopecia, taste changes, and it is absolutely teratogenic", "It's a chemotherapy infusion", "It has no significant side effects"], a: 1, r: "Vismodegib targets the Hedgehog pathway (abnormally activated in most BCCs). Important: it is teratogenic (pregnancy test before starting, strict contraception), causes muscle spasms and dysgeusia (taste changes) that affect quality of life.", s: "CAT - Skin Cancer" },
  { q: "A nurse is performing skin assessments on an immunosuppressed patient. The nurse palpates a firm, painless, rapidly growing violaceous (purple) nodule on the forearm. This could represent:", o: ["A benign cyst", "Merkel cell carcinoma — a rare but aggressive neuroendocrine skin cancer that appears as a firm, painless, rapidly growing purple/red nodule in immunosuppressed or elderly patients", "A lipoma", "Normal skin aging"], a: 1, r: "Merkel cell carcinoma: firm, painless, rapidly growing, violaceous nodule. Think 'AEIOU': Asymptomatic, Expanding rapidly, Immunosuppressed, Older (>50), UV-exposed. Very aggressive — requires prompt biopsy and multidisciplinary treatment.", s: "CAT - Skin Cancer" },
  { q: "A patient with melanoma in situ (Breslow 0 mm) asks if they need chemotherapy. The nurse explains:", o: ["Yes, chemotherapy is always needed for melanoma", "Melanoma in situ is Stage 0 — it is confined to the epidermis and is cured with surgical excision with 5 mm margins; no chemotherapy, immunotherapy, or lymph node evaluation is needed", "They need radiation therapy", "They need immunotherapy"], a: 1, r: "Melanoma in situ has not invaded beyond the basement membrane. Wide local excision with 5 mm margins is curative (essentially 100% survival). No systemic therapy or nodal evaluation needed. Regular follow-up surveillance is important.", s: "CAT - Skin Cancer" },
  { q: "A patient undergoing Mohs surgery for a BCC on the nose asks why the surgeon is doing it in stages rather than one cut. The nurse explains:", o: ["The surgeon is being extra cautious", "Mohs removes one thin layer at a time, examining each layer under the microscope immediately — this ensures ALL cancer cells are removed while preserving the maximum amount of healthy tissue, especially important on the face", "It takes longer to bill more", "Standard excision is always better"], a: 1, r: "Mohs: layer-by-layer removal with immediate microscopic margin examination achieves 99% cure rate for BCC while preserving maximum healthy tissue. Particularly valuable for cosmetically/functionally sensitive areas where tissue conservation is critical.", s: "CAT - Skin Cancer" },
  { q: "A patient with BRAF V600E-mutated melanoma is started on combination BRAF/MEK inhibitor therapy. After 3 weeks, they develop new skin lesions that are biopsied as squamous cell carcinoma. The nurse understands:", o: ["The melanoma has spread", "Paradoxical SCC development is a known side effect of BRAF inhibitors — the MEK inhibitor combination reduces this risk; the SCCs are typically low-grade and treated with excision", "These are unrelated findings", "Stop all treatment immediately"], a: 1, r: "BRAF inhibitors can paradoxically activate the MAP kinase pathway in BRAF-wild-type cells, promoting SCC development (15-30% with monotherapy). Adding a MEK inhibitor reduces this risk to 2-3%. The SCCs are usually well-differentiated and easily treated.", s: "CAT - Skin Cancer" },
  { q: "A nurse is counseling a patient who had a thin melanoma (0.5 mm) excised 5 years ago and has been cancer-free. The patient asks about discontinuing follow-up visits. The nurse advises:", o: ["You can stop follow-up after 5 years", "Melanoma can recur even decades later — continue annual skin exams for life, monthly self-skin exams, and report any new or changing lesions immediately", "No further monitoring needed", "Only see a dermatologist if new symptoms develop"], a: 1, r: "Melanoma has a unique ability to recur many years (even decades) after initial treatment. While 5-year recurrence-free survival is excellent for thin melanomas, lifetime surveillance is standard. Also, these patients are at increased risk for a second primary melanoma.", s: "CAT - Skin Cancer" },
  { q: "A nurse notices that a patient's 'moles' all look very similar — small, round, brown, symmetric. However, there is ONE lesion that looks completely different: larger, darker, asymmetric. The nurse recognizes this as:", o: ["One mole among many — not concerning", "The 'ugly duckling' sign — this outlier lesion needs dermatologic evaluation regardless of whether it meets all ABCDE criteria, because it is distinctly different from the patient's other nevi", "A birthmark", "Normal mole variation"], a: 1, r: "The 'ugly duckling' sign identifies melanomas that may not individually meet all ABCDE criteria but stand out as different from a patient's other moles. This pattern recognition approach catches melanomas that ABCDE alone might miss.", s: "CAT - Skin Cancer" }
];
